zing: content-box; // 1\n  overflow: visible; // 2\n}\n\n// ============\n// 1. Remove the gray background on active links in IE 10.\n// 2. Remove gaps in links underline in iOS 8+ and Safari 8+.\na {\n  background-color: transparent; // 1\n  -webkit-text-decoration-skip: objects; // 2\n}\n\n// ============\n// Remove the outline on focused links when they are also active or hovered\n// in all browsers (opinionated).\na:active,\na:hover {\n  outline-width: 0;\n}\n\n// ============\n// 1. Remove the border on images inside links in IE 10-.\n// 2. Don't allow images to overflow their content\nimg {\n  border-style: none; // 1\n  max-width: 100%; // 2\n}\n\n// ============\n// Hide the overflow in IE.\nsvg:not(:root) {\n  overflow: hidden;\n}\n\n// ============\n// Forms\n// 1. Change the font styles in all browsers (opinionated).\n// 2. Remove the margin in Firefox and Safari.\nbutton,\nfigure,\ninput,\noptgroup,\nselect,\ntextarea {\n  font-style: normal;\n  font-size: 100%; // 1\n  line-height: 1.15; // 1\n  margin: 0; // 2\n}\n\n// ============\n// Show the overflow in IE.\n// 1. Show the overflow in Edge.\nbutton,\ninput {\n  overflow: visible; // 1\n}\n\n// ============\n// Remove the inheritance of text transform in Edge, Firefox, and IE.\n// 1. Remove the inheritance of text transform in Firefox.\nbutton,\nselect {\n  text-transform: none; // 1\n}\n\n// ============\n// 1. Prevent a WebKit bug where (2) destroys native `audio` and `video`\n//    controls in Android 4.\n// 2. Correct the inability to style clickable types in iOS and Safari.\nbutton,\nhtml [type=\"button\"], // 1\n[type=\"reset\"],\n[type=\"submit\"] {\n  -webkit-appearance: button; // 2\n}\n\n// ============\n// Remove the inner border and padding in Firefox.\nbutton::-moz-focus-inner,\n[type='button']::-moz-focus-inner,\n[type='reset']::-moz-focus-inner,\n[type='submit']::-moz-focus-inner {\n  border-style: none;\n  padding: 0;\n}\n\n// ============\n// Ensure button hover cursor state\n[role='button']:not([disabled]),\nbutton:not([disabled]) {\n  cursor: pointer;\n}\n\nbutton[disabled] {\n  cursor: not-allowed;\n}\n\n// ============\n// Restore the focus styles unset by the previous rule.\nbutton:-moz-focusring,\n[type='button']:-moz-focusring,\n[type='reset']:-moz-focusring,\n[type='submit']:-moz-focusring {\n  outline: 1px dotted ButtonText;\n}\n\n// ============\n// Remove the default vertical scrollbar in IE.\ntextarea {\n  overflow: auto;\n}\n\n// ============\n// 1. Add the correct box sizing in IE 10-.\n// 2. Remove the padding in IE 10-.\n[type='checkbox'],\n[type='radio'] {\n  box-sizing: border-box; // 1// ============\n  padding: 0; // 2// ============\n}\n\n// ============\n// Correct the cursor style of increment and decrement buttons in Chrome.\n[type='number']::-webkit-inner-spin-button,\n[type='number']::-webkit-outer-spin-button {\n  height: auto;\n}\n\n// ============\n// 1. Correct the odd appearance in Chrome and Safari.\n// 2. Correct the outline style in Safari.\n[type='search'] {\n  -webkit-appearance: textfield; // 1// ============\n  outline-offset: -2px; // 2// ============\n}\n\n// ============\n// Remove the inner padding and cancel buttons in Chrome and Safari on OS X.\n[type='search']::-webkit-search-cancel-button,\n[type='search']::-webkit-search-decoration {\n  -webkit-appearance: none;\n}\n\n// ============\n// 1. Correct the inability to style clickable types in iOS and Safari.\n// 2. Change font properties to `inherit` in Safari.\n::-webkit-file-upload-button {\n  -webkit-appearance: button; // 1// ============\n  font: inherit; // 2// ============\n}\n\n// ============\n// Hide IE default input action icons\n::-ms-clear,\n::-ms-reveal {\n  display: none;\n}\n","@use '../../Foundation/Variables/ColorVars.scss' as colors;\n@use '../../Foundation/Variables/FontVars.scss' as fonts;\n@use '../../Foundation/Utilities/Hover.scss' as hover;\n\n// ============\n// $LINK\n// ============\n\na {\n  color: colors.$txt-link;\n  @include fonts.font-regular;\n  display: inline-block; // By setting them in inline block they stay together and fixes an issue with REACT adding display block and the borders dropping off.\n  position: relative;\n  transition: all 0.3s ease(expo-in-out);\n  text-underline-offset: 0em;\n  text-underline-position: under;\n\n  &:visited {\n    color: colors.$visited;\n  }\n\n  &:hover {\n    color: colors.$brand-primary;\n\n    &:before {\n      background-color: colors.$brand-primary;\n    }\n  }\n\n  &:disabled {\n    color: colors.$disabled-color;\n    box-shadow: none;\n\n    &:hover {\n      cursor: not-allowed;\n    }\n  }\n\n  &.lui-link-icon {\n    box-shadow: none;\n    &-disabled {\n      box-shadow: none;\n      color: colors.$disabled-color;\n      &:hover {\n        cursor: not-allowed;\n      }\n    }\n  }\n\n  &.lui-button:before {\n    display: none;\n  }\n}\n\n// Is Link being used?\n.Link {\n  color: colors.$txt-link;\n  @include hover.hover('is-active') {\n    color: colors.$txt-link;\n  }\n}\n\n.Link--reversed {\n  color: colors.$white;\n  @include hover.hover('is-active') {\n    color: colors.$charcoal;\n  }\n}\n\n.lui-external-link {\n  padding-right: 26px;\n  position: relative;\n\n  i {\n    position: absolute;\n    right: 0;\n    width: 24px;\n    height: 24px;\n  }\n}\n","@use \"sass:color\";\n// ============\n// Colours\n// ============\n\n// Colours are hard. We've remapped the names in FigLui so that's what's below.\n\n// ----------------------------\n// Brand\n// ----------------------------\n\n// Blues\n$teal: #00425d;\n$sea: #007198;\n$electric: #0096cc;\n$spray: #73c8e1;\n$polar: #e2f3f7;\n$linz-linear-gradient-blue: linear-gradient(70deg, $teal 12%, $sea 100%);\n\n// Teals\n$sherpa: #004b50;\n$surfie: #017a76;\n$persian: #00a599;\n$downy: #73cdc8;\n$iceberg: #dcf5f0;\n$linz-linear-gradient-teal: linear-gradient(270deg, $persian 1%, $downy 100%);\n\n// Greens\n$sacramento: #004e32;\n$salem: #08814d;\n$pigment: #0aa245;\n$granny: #9bd79b;\n$panache: #e9fae7;\n\n// ----------------------------\n// Neutrals\n// ----------------------------\n\n$charcoal: #2a292c;\n$fuscous: #6b6966;\n$gray: #989189;\n$silver: #beb9b4;\n$lily: #eaeaea;\n$dew: #DAD7D6;\n$hint: #f9f9f9;\n$snow: #ffffff;\n$white: $snow;\n\n// ----------------------------\n// Reserved\n// ----------------------------\n\n$engine: #cc0000;\n$carrot: #EA6A2E;\n$kendall: #F5CCCC;\n$elizabeth: #FBDED0;\n$andrea: #3A7CDF;\n$celestial: #D7E5F9;\n$golf: #0AA345;\n$memesia: #1F69C3;\n\n\n// error\n$error: $engine;\n$error-bg: $kendall; \n$error-focus: #5a0000;\n\n// warning\n$warning: $carrot;\n$warning-bg: #fbdfd2;\n$warning-focus: #b33a01;\n\n// info\n$info: $andrea;\n$info-bg: #d8e5f9;\n\n// success\n$success: $pigment;\n$success-bg: $panache;\n\n// text link\n$txt-link: $memesia;\n$test-pink: #f09;\n\n// --------------------------------------------------------\n// Deprecated variable sets\n// --------------------------------------------------------\n\n$grey-80: $charcoal;\n$grey-60: $fuscous;\n$grey-30: $gray;\n$grey-20: $silver;\n$grey-10: $lily;\n$grey-05: $hint;\n\n$blue-100: $teal;\n$blue-75: $sea;\n$blue-50: $electric;\n$blue-25: $spray;\n$blue-05: $polar;\n\n$teal-100: $sherpa;\n$teal-75: $surfie;\n$teal-50: $persian;\n$teal-25: $downy;\n$teal-05: $iceberg;\n\n$green-100: $sacramento;\n$green-75: $salem;\n$green-50: $pigment;\n$green-25: $granny;\n$green-05: $panache;\n\n$brand-primary: $sherpa;\n$brand-secondary: $surfie;\n\n// System colours\n\n$visited: $teal;\n$selection: lighten($spray, 20%);\n\n// restricted colours for btn hover states\n$primary-hover-btn: #005678;\n$primary-active-btn: $teal;\n\n$secondary-hover-btn: $polar;\n$secondary-active-btn: $sea;\n\n$tertiary-hover-btn: $polar;\n$tertiary-active-btn: $sea;\n$tertiary-btn: #f0f;\n\n$green-hover: #107c3a;\n$green-active: #094a22;\n$green-btn: $success;\n\n$error-hover-btn: #8f0000;\n$error-active-btn: #5a0000;\n\n//Restricted colours for spatial maps\n$hot-pink: #f81bef;\n\n//Type\n$heading-color: $surfie;\n$heading-color--secondary: $charcoal;\n$base-type-color: $charcoal;\n\n// Icons, inputs & radio/checkboxes\n$input-text: $charcoal;\n$input-placeholder: $fuscous;\n$input-placeholder-when-disabled: $gray;\n$base-icon-color: $sea;\n$disabled-color: $gray;\n$disabled-bg-color: $lily;\n$disabled-color-dark: $fuscous;\n$input-focus: $teal;\n\n//LINZ public site colour variables\n\n$linz-color-primary: #023d48;\n$linz-color-primary-hover: #01818a;\n\n$linz-color-tertiary: #e1e44a;\n$linz-color-tertiary-hover: #cdcf59;\n","///////////////////////////////////////////\n// Base definition of our font variables //\n///////////////////////////////////////////\n\n$base-line-height: 1.5;\n$base-font-size: 16px;\n\n//Adjust these to your font – don't need all of them if you don't need\n$base-font--combined: 'Open Sans', system-ui, sans-serif;\n\n// =====================\n// Font Mixins\n// =====================\n// These mixins are just to bundle up code snippets – instead of extending, you can use these to add\n// common styles without having a relationship created. Also, you can use different Mixins at different breakpoints.\n//\n// Feel free to adjust/rename as required. We will use these to setup our generic type styles in the next section.\n\n@mixin font-light {\n  font-family: $base-font--combined;\n  font-style: normal;\n  font-weight: 300;\n}\n\n@mixin font-regular {\n  font-family: $base-font--combined;\n  font-style: normal;\n  font-weight: normal;\n}\n\n@mixin font-italic {\n  font-family: $base-font--combined;\n  font-style: italic;\n  font-weight: normal;\n}\n\n@mixin font-semibold {\n  font-family: $base-font--combined;\n  font-style: normal;\n  font-weight: 600;\n}\n\n@mixin font-bold {\n  font-family: $base-font--combined;\n  font-style: normal;\n  font-weight: 700;\n}\n\n@mixin font-header {\n  font-family: $base-font--combined;\n  font-style: normal;\n  font-weight: 300;\n}\n\n// =====================\n// Margin Mixin\n// =====================\n\n// This is purely for creating vertical rhythm on typography if you want to use it\n$base: 16 * ($base-font-size * 0.01);\n$leading: $base * $base-line-height;\n\n@mixin type-margin-bottom($number) {\n  margin-bottom: #{$number * $leading + 'px'};\n  margin-bottom: #{$number * $line-height + 'rem'};\n}\n","// ============\n// $HOVER ACTIVE FOCUS\n// ============\n//\n// Can take an optional class name\n// @USAGE\n// @include hover('is-active') {\n// \tcolor: red;\n// \ttext-decoration: underline;\n// }\n\n@mixin hover($class: '') {\n  &:focus,\n  &:hover,\n  &:active {\n    @content;\n  }\n  @if $class != '' {\n    &.#{$class} {\n      @content;\n    }\n  }\n}\n","@use \"../../Foundation/Variables\" as lui;\n\n////////////////////////////////////////////////////////\n// Let's be honest gang, we never seem to want normal\n// list styles so here blow it away.\n///////////////////////////////////////////////////////\n\nul {\n  margin: 0;\n  padding: 0;\n  list-style-type: none;\n\n  ul,\n  li {\n    margin: 0;\n    padding: 0;\n  }\n}\n\n// This is used to add generic list styles to ul & li's\n.lui-list-bullet {\n  list-style-type: disc;\n  padding-left: lui.$unit-md; // 24px\n\n  li {\n    margin-top: lui.$unit-sm; // 12px\n  }\n}\n",'// These are for defining  global spacing units – might not be neccessary but helps with consistency – talk to the designer to see if these will help, and whether useful in your use case\n\n@use "sass:math";\n\n// Grid variables and margins\n\n$base-unit: 0.5rem; // changes base unit to 8px\n\n$unit-xxs: $base-unit * 0.5; // 4px\n$unit-xs: $base-unit; // 8px\n$unit-sm: $base-unit * 1.5; // 12px\n$unit-rg: $base-unit * 2; // 16px // NOTE: chose an additive approach – ideally these numbers would shuffle down\n$unit-md: $base-unit * 3; // 24px\n$unit-lg: $base-unit * 4; // 32px\n$unit-xl: $base-unit * 6; // 48px\n$unit-xxl: $base-unit * 10; // 80px\n\n/**\n  @deprecated\n */\n$px: 24px;\n/**\n  @deprecated\n */\n$v: $px;\n/**\n  @deprecated\n */\n$h: $v;\n','@use \'../../Foundation/Variables/ColorVars.scss\' as colors;\n\n// ============\n// Todo\n// ============\n// Utility for highlighting items on the page as "Todo", visually, without affecting box sizing.\n// Can also override the text with a `data-todo` attribute\n//\n// e.g.\n//  Render a flashing border with a banner containing "Todo"\n//    <div class="Something u-todo"> … </div>\n//\n//  Render a flashing border with a banner containing the words "Not working"\n//    <div class="Something u-todo" data-todo="Not working"> … </div>\n//\n\n// ============\n// Config\n// ============\n$todo-color: colors.$test-pink;\n$todo-text-color: colors.$white;\n$todo-throb-speed: 1.2s;\n\n// ============\n// Animations\n// ============\n@keyframes border-throb {\n  100% {\n    box-shadow: 0 0 4px 3px transparentize($todo-color, 0.7);\n  }\n}\n@keyframes throb-fade {\n  100% {\n    opacity: 0.3;\n  }\n}\n\n// ============\n// Utility\n// ============\n// Flashing border\n.u-todo {\n  position: relative;\n  box-shadow: 0 0 4px 3px $todo-color;\n  border-collapse: separate; // Needed for IE\n  border-radius: 5px;\n  opacity: 0.8;\n\n  animation: border-throb $todo-throb-speed alternate linear infinite;\n\n  // Flashing banner\n  &::before {\n    content: \'Todo\';\n\n    position: absolute;\n    padding: 4px 8px;\n    border-radius: 4px;\n    white-space: nowrap;\n\n    background-color: $todo-color;\n    color: $todo-text-color;\n    opacity: 0.8;\n\n    left: 0;\n    top: 0;\n\n    transform: translate(-50%, -50%) scale(1) rotate(-45deg);\n\n    animation: throb-fade $todo-throb-speed alternate linear infinite;\n  }\n\n  // Data attribute override\n  &[data-todo]::before {\n    content: attr(data-todo);\n  }\n}\n',"@use '../../Foundation/Variables/FontVars.scss' as fonts;\n@use '../../Foundation/Variables/ColorVars.scss' as colors;\n@use \"../../Foundation/Variables/SpacingVars.scss\" as spacing;\n@use \"../../Foundation/Variables/BreakpointVars.scss\" as *;\n@use '../../Foundation/Utilities/' as *;\n\n////////////////////////////////////////\n//      Global Typography styling     //\n////////////////////////////////////////\n\n// If you're looking for where we introduce fonts into our project, you're looking for `fonts.scss`\n\n////////////////////////////////////////////\n// Base definition of our global settings //\n////////////////////////////////////////////\n\nhtml {\n  @include fonts.font-light();\n  font-size: fonts.$base-font-size;\n  line-height: fonts.$base-line-height;\n  color: colors.$base-type-color;\n  // Better Font Rendering\n  font-feature-settings: 'kern' 1;\n  font-kerning: normal;\n  text-rendering: optimizeLegibility;\n  -webkit-font-smoothing: antialiased;\n  -moz-osx-font-smoothing: grayscale;\n}\n\n// Text highlight color\n// NOTE: must be specified individually\n//highlight colour when selecting text on the page\n\n::selection {\n  background: colors.$selection; /* WebKit/Blink Browsers */\n  color: colors.$brand-primary;\n}\n::-moz-selection {\n  background: colors.$selection; /* Gecko Browsers */\n  color: colors.$brand-primary;\n}\n\nem,\ni {\n  @include fonts.font-italic;\n}\nstrong,\nb {\n  @include fonts.font-semibold;\n}\n\nsub,\nsup {\n  @extend %small !optional;\n  line-height: 0;\n}\n\nhr {\n  border: none;\n  margin: 0;\n  background-color: colors.$charcoal;\n  height: 1px;\n}\n\n// Phone numbers ============\n// Avoid wrapping phone numbers onto multiple lines\n[href='tel'] {\n  white-space: nowrap;\n}\n\n// =====================\n// Typography variables\n// =====================\n\n// Adjust naming of these as you see fit\n// It is suggested to have something that describes the utility that the font is being used for – here we're assuming heading font and body font are discrete use-cases\n\n// =====================\n// Typography variables\n// =====================\n\n// Adjust naming of these as you see fit\n// It is suggested to have something that describes the utility that the font is being used for – here we're assuming heading font and body font are discrete use-cases\n\n// =====================\n// Headings\n// =====================\n\nh1,\nh2,\nh3,\nh4,\nh5,\nh6,\np {\n  line-height: 1.5;\n  margin-bottom: 0;\n}\n\nh1,\n.h1,\nh2,\n.h2,\nh3,\n.h3,\nh4,\n.h4,\nh5,\n.h5,\nh6,\n.h6 {\n  color: colors.$heading-color;\n}\n\nh1,\n.h1 {\n  @include fonts.font-light();\n  font-size: toRem(44px);\n\n  & + p {\n    margin-top: spacing.$unit-sm; //32px\n  }\n}\n\nh2,\n.h2 {\n  @include fonts.font-light();\n  font-size: toRem(32px);\n  margin-top: spacing.$unit-xl; // 96px\n\n  & + p {\n    margin-top: spacing.$unit-sm; // 32px\n  }\n}\n\nh3,\n.h3 {\n  @include fonts.font-regular();\n  font-size: toRem(26px);\n  margin-top: spacing.$unit-lg; // 64px\n\n  & + p {\n    margin-top: spacing.$unit-sm; // 32px\n  }\n}\n\nh4,\n.h4 {\n  @include fonts.font-regular();\n  font-size: toRem(22px);\n  margin-top: spacing.$unit-lg; // 64px\n\n  & + p {\n    margin-top: spacing.$unit-sm; // 32px\n  }\n}\n\nh5,\n.h5 {\n  @include fonts.font-semibold();\n  font-size: toRem(18px);\n}\n\nh6,\n.h6 {\n  @include fonts.font-semibold();\n  font-size: toRem(16px);\n}\n\n// =====================\n// Body\n// =====================\n\np,\n.p {\n  @include fonts.font-light();\n  font-size: toRem(16px);\n  margin-top: spacing.$unit-lg; //64px\n}\n\np.lui-small {\n  @include fonts.font-light();\n  font-size: toRem(13px);\n  line-height: toRem(20px);\n  margin-top: spacing.$unit-lg; //64px\n}\n\n// ====================================================================================\n// Headings 22/02/2022 – these are the next iteration of typographic updates\n// These will replace the type above and the picket fence will be removed\n// To view the changes in your app, add the class LuiBeta-fonts220222\n// ====================================================================================\n\n.LuiBeta-fonts220222 {\n  h1,\n  .h1 {\n    @include fonts.font-light();\n    @include fluidType--size(34px, 44px, $breakpoint-sm, $breakpoint-xl);\n    @include fluidType--lineHeight(44px, 52px, $breakpoint-sm, $breakpoint-xl);\n\n    & + p {\n      margin-top: spacing.$unit-sm; //32px\n    }\n  }\n\n  h2,\n  .h2 {\n    @include fonts.font-light();\n    @include fluidType--size(28px, 32px, $breakpoint-sm, $breakpoint-xl);\n    @include fluidType--lineHeight(36px, 40px, $breakpoint-sm, $breakpoint-xl);\n    margin-top: spacing.$unit-xl; // 96px\n\n    & + p {\n      margin-top: spacing.$unit-sm; // 32px\n    }\n  }\n\n  h3,\n  .h3 {\n    @include fonts.font-regular();\n    @include fluidType--size(24px, 24px, $breakpoint-sm, $breakpoint-xl);\n    @include fluidType--lineHeight(32px, 32px, $breakpoint-sm, $breakpoint-xl);\n    letter-spacing: 0.2px;\n    margin-top: spacing.$unit-lg; // 64px\n\n    & + p {\n      margin-top: spacing.$unit-sm; // 32px\n    }\n  }\n\n  h4,\n  .h4 {\n    @include fonts.font-regular();\n    @include fluidType--size(20px, 20px, $breakpoint-sm, $breakpoint-xl);\n    @include fluidType--lineHeight(24px, 24px, $breakpoint-sm, $breakpoint-xl);\n    letter-spacing: 0.2px;\n    margin-top: spacing.$unit-lg; // 64px\n\n    & + p {\n      margin-top: spacing.$unit-sm; // 32px\n    }\n  }\n\n  h5,\n  .h5 {\n    @include fonts.font-semibold();\n    @include fluidType--size(16px, 16px, $breakpoint-sm, $breakpoint-xl);\n    @include fluidType--lineHeight(24px, 22px, $breakpoint-sm, $breakpoint-xl);\n  }\n\n  h6,\n  .h6 {\n    @include fonts.font-semibold();\n    @include fluidType--size(14px, 14px, $breakpoint-sm, $breakpoint-xl);\n    @include fluidType--lineHeight(18px, 18px, $breakpoint-sm, $breakpoint-xl);\n    letter-spacing: 0.2px;\n  }\n\n  // =====================\n  // Body\n  // =====================\n\n  p,\n  .p {\n    @include fonts.font-light();\n    font-size: toRem(16px);\n    margin-top: spacing.$unit-lg; //64px\n  }\n\n  p.lui-small {\n    @include fonts.font-light();\n    font-size: toRem(13px);\n    line-height: toRem(20px);\n    margin-top: spacing.$unit-lg; //64px\n  }\n}\n","// ==========================================\n// $Fluid Type\n// ==========================================\n// see: https://css-tricks.com/books/fundamental-css-tactics/scale-typography-screen-size/\n// The idea is that you set the bounds/breakpoints of when the values scale\n//\n// Caveat is min-breakpoint needs to at least be 1px so if it's not compiling then that's your problem\n// You can put in breakpoints that match the project with the following (set in Breakpoints.scss)\n// $breakpoint-sm\n// $breakpoint-md\n// $breakpoint-lg\n// $breakpoint-xl\n// $breakpoint-xxl\n//\n// ==========================================\n\n@use \"sass:math\";\n\n@function strip-unit($value) {\n  @return math.div($value, $value * 0 + 1);\n}\n\n@mixin fluidType--size(\n  $min-size,\n  $max-size,\n  $min-breakpoint: 1px,\n  $max-breakpoint\n) {\n  $u1: unit($min-breakpoint);\n  $u2: unit($max-breakpoint);\n  $u3: unit($min-size);\n  $u4: unit($max-size);\n\n  @if $u1 == $u2 and $u1 == $u3 and $u1 == $u4 {\n    & {\n      font-size: $min-size;\n      @media screen and (min-width: $min-breakpoint) {\n        font-size: calc(\n          #{$min-size} + #{strip-unit($max-size - $min-size)} *\n            (\n              (100vw - #{$min-breakpoint}) / #{strip-unit(\n                  $max-breakpoint - $min-breakpoint\n                )}\n            )\n        );\n      }\n\n      @media screen and (min-width: $max-breakpoint) {\n        font-size: $max-size;\n      }\n    }\n  }\n}\n\n@mixin fluidType--lineHeight(\n  $min-size: 1px,\n  $max-size,\n  $min-breakpoint: 1px,\n  $max-breakpoint\n) {\n  $u1: unit($min-size);\n  $u2: unit($max-size);\n  $u3: unit($min-breakpoint);\n  $u4: unit($max-breakpoint);\n\n  @if $u1 == $u2 and $u1 == $u3 and $u1 == $u4 {\n    & {\n      line-height: $min-size;\n      @media screen and (min-width: $min-breakpoint) {\n        line-height: calc(\n          #{$min-size} + #{strip-unit($max-size - $min-size)} *\n            (\n              (100vw - #{$min-breakpoint}) / #{strip-unit(\n                  $max-breakpoint - $min-breakpoint\n                )}\n            )\n        );\n      }\n\n      @media screen and (min-width: $max-breakpoint) {\n        line-height: $max-size;\n      }\n    }\n  }\n}\n","@use '../../Foundation/Variables/BreakpointVars.scss' as breakpoints;\n@use '../../Foundation/Utilities/' as *;\n///////////////////////////////\n// Container\n///////////////////////////////\n\n// Need to explain what's going on here –\n// So we are adding a little padding left and right of both sides of container to make sure content doesn't butt right up against the edges. It adds the container padding on the inside to give a little breathing room in containers. The next step is to ensure that the padding doesn't reduce the size of the breakpoint so we add it back to the breakpoint.\n\n// There is also a variation that removed the padding and just lets content hit the sides.\n\n$container-padding: 2.5%;\n\n%Container {\n  display: block;\n  margin: 0 auto;\n}\n\n%Container--paddingOnly {\n  padding: 0 $container-padding;\n}\n\n%Container--noPadding {\n  max-width: breakpoints.$breakpoint1;\n\n  @include breakpoint(sm) {\n    max-width: breakpoints.$breakpoint2;\n  }\n\n  @include breakpoint(md) {\n    max-width: breakpoints.$breakpoint3;\n  }\n\n  @include breakpoint(lg) {\n    max-width: breakpoints.$breakpoint4;\n  }\n}\n\n%Container--padding {\n  padding: 0 $container-padding;\n  max-width: calc(#{breakpoints.$breakpoint1} + (#{$container-padding} * 2));\n\n  @include breakpoint(sm) {\n    max-width: calc(#{breakpoints.$breakpoint2} + (#{$container-padding} * 2));\n  }\n\n  @include breakpoint(md) {\n    max-width: calc(#{breakpoints.$breakpoint3} + (#{$container-padding} * 2));\n  }\n\n  @include breakpoint(lg) {\n    max-width: calc(#{breakpoints.$breakpoint4} + (#{$container-padding} * 2));\n  }\n}\n\n.Container {\n  @extend %Container;\n  @extend %Container--padding;\n}\n\n.Container--noPadding {\n  @extend %Container;\n  @extend %Container--noPadding;\n}\n\n.Container--paddingOnly {\n  @extend %Container;\n  @extend %Container--paddingOnly;\n}\n","/////////////////////////////////////\n// Breakpoints\n/////////////////////////////////////\n\n// This is based around 'mobile-first' development and design. The idea is to turn off styles as you increase in breakpoint size.\n\n$breakpoint1: 480px;\n$breakpoint2: 768px;\n$breakpoint3: 1024px;\n$breakpoint4: 1280px;\n$breakpoint5: 1600px;\n\n// Following is for mixins such as Fluid Type to use\n\n$breakpoint-sm: $breakpoint1;\n$breakpoint-md: $breakpoint2;\n$breakpoint-lg: $breakpoint3;\n$breakpoint-xl: $breakpoint4;\n$breakpoint-xxl: $breakpoint5;\n",'@use "../Variables/BreakpointVars.scss" as *;\n\n@mixin breakpoint($breakpoint) {\n  @if ($breakpoint == sm) {\n    @media screen and (min-width: #{$breakpoint1}) {\n      @content;\n    }\n  } @else if ($breakpoint == md) {\n    @media screen and (min-width: #{$breakpoint2}) {\n      @content;\n    }\n  } @else if ($breakpoint == lg) {\n    @media screen and (min-width: #{$breakpoint3}) {\n      @content;\n    }\n  } @else if ($breakpoint == xl) {\n    @media screen and (min-width: #{$breakpoint4}) {\n      @content;\n    }\n  } @else if ($breakpoint == xxl) {\n    @media screen and (min-width: #{$breakpoint5}) {\n      @content;\n    }\n  } @else {\n    @media screen and (min-width: #{$breakpoint}) {\n      @content;\n    }\n  }\n}\n',"@use '../../Foundation/Variables/ColorVars.scss' as colors;\n@use '../../Foundation/Variables/BreakpointVars.scss' as breakpoints;\n\n// ==========================================\n// Main layout\n// ==========================================\n\nhtml {\n  height: 100%;\n  overflow: visible;\n  min-height: auto;\n  scroll-behavior: smooth;\n}\n\nbody {\n  height: 100%;\n  min-height: 100vh;\n  overflow-y: auto;\n  -webkit-overflow-scrolling: touch;\n  margin: 0;\n}\n\n// set universal box sizing, plus the declaration in the HTML above\n*,\n*:before,\n*:after {\n  box-sizing: inherit;\n}\n\n#root {\n  height: 100%;\n}\n\n.Main {\n  display: grid;\n  min-height: 100%;\n  grid-template-areas:\n    'Header'\n    'Content'\n    'Footer';\n  grid-template-rows: auto 1fr auto;\n  grid-template-columns: minmax(\n    0,\n    1fr\n  ); //Good catch from Darrell – our tables were blowing out and this fixes it https://css-tricks.com/preventing-a-grid-blowout/\n}\n\n.Content {\n  grid-area: Content;\n}\n\n// ! ************************************************\n// ! TODO: Move these two to their actual components\n// ! ************************************************\n.lui-header-primary {\n  grid-area: Header;\n}\n\n.lui-footer {\n  grid-area: Footer;\n}\n\n// ! ************************************************\n// ! TODO: Figure out where to place this\n// ! ************************************************\n\n.lui-section-dark {\n  background-color: colors.$hint;\n  border-top: 1px solid colors.$lily;\n  border-bottom: 1px solid colors.$lily;\n}\n","@use '../Foundation/Variables/SpacingVars.scss' as spacing;\n@use '../Foundation/Variables/BreakpointVars.scss' as breakpoints;\n@use '../Foundation/Utilities' as *;\n\n// ! ************************************************************ ! //\n// !         TODO: This whole file should be removed              ! //\n// ! ************************************************************ ! //\n\n.lui-box-shadow {\n  @include box-shadow;\n}\n\n$lui-width-xxs: 44px; // icon size\n$lui-width-xs: 122px;\n$lui-width-sm: 220px;\n$lui-width-md: 360px;\n$lui-width-lg: 480px;\n$lui-width-xl: 620px;\n\n// reserved for helper classes only\n\n.lui-full-width {\n  width: 100%;\n}\n\n.lui-half-width {\n  width: 50%;\n}\n\n.lui-width-xxs {\n  width: $lui-width-xxs;\n}\n\n.lui-width-xs {\n  width: $lui-width-xs;\n}\n\n.lui-width-sm {\n  width: $lui-width-sm;\n}\n\n.lui-width-md {\n  width: $lui-width-md;\n}\n\n.lui-width-lg {\n  width: $lui-width-lg;\n}\n\n.lui-width-xl {\n  width: $lui-width-xl;\n}\n\n.lui-max-width {\n  max-width: 100% !important;\n}\n\n.lui-remove-border-bottom {\n  border-bottom: none !important;\n}\n\n// accessiblity -----------------------------------------\n\n.LuiScreenReadersOnly {\n  @include ScreenReadersOnly;\n}\n\n// Alignment -----------------------------------------\n\n.lui-align-right {\n  text-align: right;\n}\n\n.lui-align-top {\n  vertical-align: top;\n}\n\n.lui-align-bottom {\n  vertical-align: bottom;\n}\n\n.lui-align-baseline {\n  vertical-align: baseline;\n}\n\n.lui-align-baseline {\n  vertical-align: middle;\n}\n\n.lui-justify-space-between {\n  justify-content: space-between;\n}\n\n.lui-items-center {\n  align-items: center;\n}\n\n//add padding to the bottom of the wrapper element so the type doesn't sit on the bottom of the container\n.lui-content-buffer {\n  padding-bottom: spacing.$unit-xl;\n}\n\n.lui-content-buffer-lg {\n  padding-bottom: spacing.$unit-lg;\n}\n\n.lui-content-buffer-xl {\n  padding-bottom: spacing.$unit-xl;\n}\n\n// Remove margins\n.lui-remove-margin-all {\n  margin: 0 !important;\n}\n\n.lui-remove-margin-x {\n  margin-left: 0 !important;\n  margin-right: 0 !important;\n}\n\n.lui-remove-margin-y {\n  margin-top: 0 !important;\n  margin-bottom: 0 !important;\n}\n\n// Remove padding\n.lui-remove-padding-all {\n  padding: 0 !important;\n}\n\n.lui-remove-padding-x {\n  padding-left: 0 !important;\n  padding-right: 0 !important;\n}\n\n.lui-remove-padding-y {\n  padding-top: 0 !important;\n  padding-bottom: 0 !important;\n}\n\n// Flexbox\n.lui-flex {\n  display: flex;\n}\n\n.lui-flex-column {\n  flex-direction: column;\n}\n\n.lui-flex-row {\n  flex-direction: row;\n}\n\n// exploration into defining dividers (border top) on various screen sizes so they can be set on the Divs in the required sequence.\n// use the selector: div[class*=\"row-divider\"] to give it a colour\n// Use .lui-row-divider class to apply a divider at all screen sizes\n// @mixin lui-row-divider {\n//   border-top: 1px solid;\n//   margin-top: spacing.$unit-md;\n//   padding-top: spacing.$unit-md;\n// }\n\n// .lui-row-divider {\n//   @include lui-row-divider;\n//   &-xs {\n//     @media only screen and (max-width: $screen-xs) {\n//       @include lui-row-divider;\n//     }\n//   }\n//   &-sm {\n//     @media only screen and (min-width: $screen-xs) and (max-width: $screen-sm) {\n//       @include lui-row-divider;\n//     }\n//   }\n//   &-md {\n//     @media only screen and (min-width: $screen-sm) and (max-width: $screen-md) {\n//       @include lui-row-divider;\n//     }\n//   }\n//   &-lg {\n//     @media only screen and (min-width: $screen-md) and (max-width: $screen-lg) {\n//       @include lui-row-divider;\n//     }\n//   }\n//   &-xl {\n//     @media only screen and (min-width: $screen-lg) and (max-width: $screen-xl) {\n//       @include lui-row-divider;\n//     }\n//   }\n// }\n\n// hide elements depending on screen size\n\n$screen-xs: breakpoints.$breakpoint1;\n\n$screen-sm-min: $screen-xs + 0.1px;\n$screen-sm: breakpoints.$breakpoint2; // 768px\n\n$screen-md-min: $screen-sm + 0.1px;\n$screen-md: breakpoints.$breakpoint3; // 1024px\n\n$screen-lg-min: $screen-md + 0.1px;\n$screen-lg: breakpoints.$breakpoint4; // 1280px\n\n$screen-xl-min: $screen-lg + 0.1px;\n$screen-xl: breakpoints.$breakpoint5; // 1600px;\n\n.lui-hide-xs {\n  @media only screen and (max-width: $screen-xs) {\n    display: none !important;\n  }\n}\n\n.lui-hide-sm {\n  @media only screen and (min-width: $screen-sm-min) and (max-width: $screen-sm) {\n    display: none !important;\n  }\n}\n\n.lui-hide-md {\n  @media only screen and (min-width: $screen-md-min) and (max-width: $screen-md) {\n    display: none !important;\n  }\n}\n\n.lui-hide-lg {\n  @media only screen and (min-width: $screen-lg-min) and (max-width: $screen-lg) {\n    display: none !important;\n  }\n}\n\n.lui-hide-xl {\n  @media only screen and (min-width: $screen-xl-min) {\n    display: none !important;\n  }\n}\n\n.lui-hide {\n  display: none;\n}\n\n// show elements depending on screen size\n\n.lui-show-xs {\n  @media only screen and (max-width: $screen-xs) {\n    display: block !important;\n  }\n}\n\n.lui-show-sm {\n  @media only screen and (min-width: $screen-sm-min) and (max-width: $screen-sm) {\n    display: block !important;\n  }\n}\n\n.lui-show-md {\n  @media only screen and (min-width: $screen-md-min) and (max-width: $screen-md) {\n    display: block !important;\n  }\n}\n\n.lui-show-lg {\n  @media only screen and (min-width: $screen-lg-min) and (max-width: $screen-lg) {\n    display: block !important;\n  }\n}\n\n.lui-show-xl {\n  @media only screen and (min-width: $screen-xl-min) {\n    display: block !important;\n  }\n}\n\n.lui-show-block {\n  display: block;\n}\n\n.lui-show-inline-block {\n  display: inline-block;\n}\n\n// margin helpers ------------------------------------\n\n@mixin margin-builder($selector, $declaration, $value) {\n  #{$selector} {\n    #{$declaration}: $value !important;\n  }\n}\n\n@mixin multi-margin-builder(\n  $selector,\n  $declaration,\n  $value,\n  $declarationTwo,\n  $valueTwo\n) {\n  #{$selector} {\n    #{$declaration}: $value !important;\n    #{$declarationTwo}: $valueTwo !important;\n  }\n}\n\n//vertical margins\n@include multi-margin-builder(\n  '.lui-margin-y-xxs',\n  'margin-top',\n  spacing.$unit-xxs,\n  'margin-bottom',\n  spacing.$unit-xxs\n);\n@include multi-margin-builder(\n  '.lui-margin-y-xs',\n  'margin-top',\n  spacing.$unit-xs,\n  'margin-bottom',\n  spacing.$unit-xs\n);\n@include multi-margin-builder(\n  '.lui-margin-y-sm',\n  'margin-top',\n  spacing.$unit-sm,\n  'margin-bottom',\n  spacing.$unit-sm\n);\n@include multi-margin-builder(\n  '.lui-margin-y-md',\n  'margin-top',\n  spacing.$unit-md,\n  'margin-bottom',\n  spacing.$unit-md\n);\n@include multi-margin-builder(\n  '.lui-margin-y-lg',\n  'margin-top',\n  spacing.$unit-lg,\n  'margin-bottom',\n  spacing.$unit-lg\n);\n@include multi-margin-builder(\n  '.lui-margin-y-xl',\n  'margin-top',\n  spacing.$unit-xl,\n  'margin-bottom',\n  spacing.$unit-xl\n);\n@include multi-margin-builder(\n  '.lui-margin-y-xxl',\n  'margin-top',\n  spacing.$unit-xxl,\n  'margin-bottom',\n  spacing.$unit-xxl\n);\n\n//horizontal margins\n@include multi-margin-builder(\n  '.lui-margin-x-xxs',\n  'margin-left',\n  spacing.$unit-xxs,\n  'margin-right',\n  spacing.$unit-xxs\n);\n@include multi-margin-builder(\n  '.lui-margin-x-xs',\n  'margin-left',\n  spacing.$unit-xs,\n  'margin-right',\n  spacing.$unit-xs\n);\n@include multi-margin-builder(\n  '.lui-margin-x-sm',\n  'margin-left',\n  spacing.$unit-sm,\n  'margin-right',\n  spacing.$unit-sm\n);\n@include multi-margin-builder(\n  '.lui-margin-x-md',\n  'margin-left',\n  spacing.$unit-md,\n  'margin-right',\n  spacing.$unit-md\n);\n@include multi-margin-builder(\n  '.lui-margin-x-lg',\n  'margin-left',\n  spacing.$unit-lg,\n  'margin-right',\n  spacing.$unit-lg\n);\n@include multi-margin-builder(\n  '.lui-margin-x-xl',\n  'margin-left',\n  spacing.$unit-xl,\n  'margin-right',\n  spacing.$unit-xl\n);\n@include multi-margin-builder(\n  '.lui-margin-x-xxl',\n  'margin-left',\n  spacing.$unit-xxl,\n  'margin-right',\n  spacing.$unit-xxl\n);\n\n//top margin\n@include margin-builder('.lui-margin-top-xxs', 'margin-top', spacing.$unit-xxs);\n\n@include margin-builder('.lui-margin-top-xs', 'margin-top', spacing.$unit-xs);\n\n@include margin-builder('.lui-margin-top-sm', 'margin-top', spacing.$unit-sm);\n\n@include margin-builder('.lui-margin-top-md', 'margin-top', spacing.$unit-md);\n\n@include margin-builder('.lui-margin-top-lg', 'margin-top', spacing.$unit-lg);\n\n@include margin-builder('.lui-margin-top-xl', 'margin-top', spacing.$unit-xl);\n\n@include margin-builder('.lui-margin-top-xxl', 'margin-top', spacing.$unit-xxl);\n\n//bottom margin\n\n@include margin-builder(\n  '.lui-margin-bottom-xxs',\n  'margin-bottom',\n  spacing.$unit-xxs\n);\n\n@include margin-builder(\n  '.lui-margin-bottom-xs',\n  'margin-bottom',\n  spacing.$unit-xs\n);\n\n@include margin-builder(\n  '.lui-margin-bottom-sm',\n  'margin-bottom',\n  spacing.$unit-sm\n);\n\n@include margin-builder(\n  '.lui-margin-bottom-md',\n  'margin-bottom',\n  spacing.$unit-md\n);\n\n@include margin-builder(\n  '.lui-margin-bottom-lg',\n  'margin-bottom',\n  spacing.$unit-lg\n);\n\n@include margin-builder(\n  '.lui-margin-bottom-xl',\n  'margin-bottom',\n  spacing.$unit-xl\n);\n\n@include margin-builder(\n  '.lui-margin-bottom-xxl',\n  'margin-bottom',\n  spacing.$unit-xxl\n);\n\n//left margin\n\n@include margin-builder(\n  '.lui-margin-left-xxs',\n  'margin-left',\n  spacing.$unit-xxs\n);\n\n@include margin-builder('.lui-margin-left-xs', 'margin-left', spacing.$unit-xs);\n\n@include margin-builder('.lui-margin-left-sm', 'margin-left', spacing.$unit-sm);\n\n@include margin-builder('.lui-margin-left-md', 'margin-left', spacing.$unit-md);\n\n@include margin-builder('.lui-margin-left-lg', 'margin-left', spacing.$unit-lg);\n\n@include margin-builder('.lui-margin-left-xl', 'margin-left', spacing.$unit-xl);\n\n@include margin-builder(\n  '.lui-margin-left-xxl',\n  'margin-left',\n  spacing.$unit-xxl\n);\n\n//right margin\n\n@include margin-builder(\n  '.lui-margin-right-xxs',\n  'margin-right',\n  spacing.$unit-xxs\n);\n\n@include margin-builder(\n  '.lui-margin-right-xs',\n  'margin-right',\n  spacing.$unit-xs\n);\n\n@include margin-builder(\n  '.lui-margin-right-sm',\n  'margin-right',\n  spacing.$unit-sm\n);\n\n@include margin-builder(\n  '.lui-margin-right-md',\n  'margin-right',\n  spacing.$unit-md\n);\n\n@include margin-builder(\n  '.lui-margin-right-lg',\n  'margin-right',\n  spacing.$unit-lg\n);\n\n@include margin-builder(\n  '.lui-margin-right-xl',\n  'margin-right',\n  spacing.$unit-xl\n);\n\n@include margin-builder(\n  '.lui-margin-right-xxl',\n  'margin-right',\n  spacing.$unit-xxl\n);\n\n// Remove margins\n.lui-remove-margin-all {\n  margin: 0 !important;\n}\n\n.lui-remove-margin-x {\n  margin-left: 0 !important;\n  margin-right: 0 !important;\n}\n\n.lui-remove-margin-y {\n  margin-top: 0 !important;\n  margin-bottom: 0 !important;\n}\n\n// ----------------- PADDING HELPERS ------------------------------------\n//padding all round\n\n@include margin-builder('.lui-padding-xxs', 'padding', spacing.$unit-xxs);\n\n@include margin-builder('.lui-padding-xs', 'padding', spacing.$unit-xs);\n\n@include margin-builder('.lui-padding-sm', 'padding', spacing.$unit-sm);\n\n@include margin-builder('.lui-padding-md', 'padding', spacing.$unit-md);\n\n@include margin-builder('.lui-padding-lg', 'padding', spacing.$unit-lg);\n\n@include margin-builder('.lui-padding-xl', 'padding', spacing.$unit-xl);\n\n@include margin-builder('.lui-padding-xxl', 'padding', spacing.$unit-xxl);\n\n//vertical padding\n@include multi-margin-builder(\n  '.lui-padding-y-xxs',\n  'padding-top',\n  spacing.$unit-xxs,\n  'padding-bottom',\n  spacing.$unit-xxs\n);\n@include multi-margin-builder(\n  '.lui-padding-y-xs',\n  'padding-top',\n  spacing.$unit-xs,\n  'padding-bottom',\n  spacing.$unit-xs\n);\n@include multi-margin-builder(\n  '.lui-padding-y-sm',\n  'padding-top',\n  spacing.$unit-sm,\n  'padding-bottom',\n  spacing.$unit-sm\n);\n@include multi-margin-builder(\n  '.lui-padding-y-md',\n  'padding-top',\n  spacing.$unit-md,\n  'padding-bottom',\n  spacing.$unit-md\n);\n@include multi-margin-builder(\n  '.lui-padding-y-lg',\n  'padding-top',\n  spacing.$unit-lg,\n  'padding-bottom',\n  spacing.$unit-lg\n);\n@include multi-margin-builder(\n  '.lui-padding-y-xl',\n  'padding-top',\n  spacing.$unit-xl,\n  'padding-bottom',\n  spacing.$unit-xl\n);\n@include multi-margin-builder(\n  '.lui-padding-y-xxl',\n  'padding-top',\n  spacing.$unit-xxl,\n  'padding-bottom',\n  spacing.$unit-xxl\n);\n\n//horizontal padding\n@include multi-margin-builder(\n  '.lui-padding-x-xxs',\n  'padding-left',\n  spacing.$unit-xxs,\n  'padding-right',\n  spacing.$unit-xxs\n);\n@include multi-margin-builder(\n  '.lui-padding-x-xs',\n  'padding-left',\n  spacing.$unit-xs,\n  'padding-right',\n  spacing.$unit-xs\n);\n@include multi-margin-builder(\n  '.lui-padding-x-sm',\n  'padding-left',\n  spacing.$unit-sm,\n  'padding-right',\n  spacing.$unit-sm\n);\n@include multi-margin-builder(\n  '.lui-padding-x-md',\n  'padding-left',\n  spacing.$unit-md,\n  'padding-right',\n  spacing.$unit-md\n);\n@include multi-margin-builder(\n  '.lui-padding-x-lg',\n  'padding-left',\n  spacing.$unit-lg,\n  'padding-right',\n  spacing.$unit-lg\n);\n@include multi-margin-builder(\n  '.lui-padding-x-xl',\n  'padding-left',\n  spacing.$unit-xl,\n  'padding-right',\n  spacing.$unit-xl\n);\n@include multi-margin-builder(\n  '.lui-padding-x-xxl',\n  'padding-left',\n  spacing.$unit-xxl,\n  'padding-right',\n  spacing.$unit-xxl\n);\n\n//top padding\n@include margin-builder(\n  '.lui-padding-top-xxs',\n  'padding-top',\n  spacing.$unit-xxs\n);\n\n@include margin-builder('.lui-padding-top-xs', 'padding-top', spacing.$unit-xs);\n\n@include margin-builder('.lui-padding-top-sm', 'padding-top', spacing.$unit-sm);\n\n@include margin-builder('.lui-padding-top-md', 'padding-top', spacing.$unit-md);\n\n@include margin-builder('.lui-padding-top-lg', 'padding-top', spacing.$unit-lg);\n\n@include margin-builder('.lui-padding-top-xl', 'padding-top', spacing.$unit-xl);\n\n@include margin-builder(\n  '.lui-padding-top-xxl',\n  'padding-top',\n  spacing.$unit-xxl\n);\n\n//bottom padding\n\n@include margin-builder(\n  '.lui-padding-bottom-xxs',\n  'padding-bottom',\n  spacing.$unit-xxs\n);\n\n@include margin-builder(\n  '.lui-padding-bottom-xs',\n  'padding-bottom',\n  spacing.$unit-xs\n);\n\n@include margin-builder(\n  '.lui-padding-bottom-sm',\n  'padding-bottom',\n  spacing.$unit-sm\n);\n\n@include margin-builder(\n  '.lui-padding-bottom-md',\n  'padding-bottom',\n  spacing.$unit-md\n);\n\n@include margin-builder(\n  '.lui-padding-bottom-lg',\n  'padding-bottom',\n  spacing.$unit-lg\n);\n\n@include margin-builder(\n  '.lui-padding-bottom-xl',\n  'padding-bottom',\n  spacing.$unit-xl\n);\n\n@include margin-builder(\n  '.lui-padding-bottom-xxl',\n  'padding-bottom',\n  spacing.$unit-xxl\n);\n\n//left padding\n\n@include margin-builder(\n  '.lui-padding-left-xxs',\n  'padding-left',\n  spacing.$unit-xxs\n);\n\n@include margin-builder(\n  '.lui-padding-left-xs',\n  'padding-left',\n  spacing.$unit-xs\n);\n\n@include margin-builder(\n  '.lui-padding-left-sm',\n  'padding-left',\n  spacing.$unit-sm\n);\n\n@include margin-builder(\n  '.lui-padding-left-md',\n  'padding-left',\n  spacing.$unit-md\n);\n\n@include margin-builder(\n  '.lui-padding-left-lg',\n  'padding-left',\n  spacing.$unit-lg\n);\n\n@include margin-builder(\n  '.lui-padding-left-xl',\n  'padding-left',\n  spacing.$unit-xl\n);\n\n@include margin-builder(\n  '.lui-padding-left-xxl',\n  'padding-left',\n  spacing.$unit-xxl\n);\n\n//right padding\n\n@include margin-builder(\n  '.lui-padding-right-xxs',\n  'padding-right',\n  spacing.$unit-xxs\n);\n\n@include margin-builder(\n  '.lui-padding-right-xs',\n  'padding-right',\n  spacing.$unit-xs\n);\n\n@include margin-builder(\n  '.lui-padding-right-sm',\n  'padding-right',\n  spacing.$unit-sm\n);\n\n@include margin-builder(\n  '.lui-padding-right-md',\n  'padding-right',\n  spacing.$unit-md\n);\n\n@include margin-builder(\n  '.lui-padding-right-lg',\n  'padding-right',\n  spacing.$unit-lg\n);\n\n@include margin-builder(\n  '.lui-padding-right-xl',\n  'padding-right',\n  spacing.$unit-xl\n);\n\n@include margin-builder(\n  '.lui-padding-right-xxl',\n  'padding-right',\n  spacing.$unit-xxl\n);\n\n// Remove padding\n.lui-remove-padding-all {\n  padding: 0 !important;\n}\n\n.lui-remove-padding-x {\n  padding-left: 0 !important;\n  padding-right: 0 !important;\n}\n\n.lui-remove-padding-y {\n  padding-top: 0 !important;\n  padding-bottom: 0 !important;\n}\n\n// exploration into defining dividers (border top) on various screen sizes so they can be set on the Divs in the required sequence.\n// use the selector: div[class*=\"row-divider\"] to give it a colour\n// Use .lui-row-divider class to apply a divider at all screen sizes\n@mixin lui-row-divider {\n  border-top: 1px solid;\n  margin-top: spacing.$unit-md;\n  padding-top: spacing.$unit-md;\n}\n\n.lui-row-divider {\n  @include lui-row-divider;\n\n  &-xs {\n    @media only screen and (max-width: $screen-xs) {\n      @include lui-row-divider;\n    }\n  }\n\n  &-sm {\n    @media only screen and (min-width: $screen-xs) and (max-width: $screen-sm) {\n      @include lui-row-divider;\n    }\n  }\n\n  &-md {\n    @media only screen and (min-width: $screen-sm) and (max-width: $screen-md) {\n      @include lui-row-divider;\n    }\n  }\n\n  &-lg {\n    @media only screen and (min-width: $screen-md) and (max-width: $screen-lg) {\n      @include lui-row-divider;\n    }\n  }\n\n  &-xl {\n    @media only screen and (min-width: $screen-lg) and (max-width: $screen-xl) {\n      @include lui-row-divider;\n    }\n  }\n}\n\n// Zebra stripes for tables etc -----------------------------------------------------------\n\n// See the table.scss for these classes\n\n// End Zebra stripes :)  -----------------------------------------------------------\n","// ============\n// Box Shadow\n// ============\n\n@mixin box-shadow {\n  box-shadow: 0 0 10px rgba(0, 0, 0, 0.2);\n}\n\n// Drop shadow declarations - Medium is default and if no value is passed. There are three variations of drop shadows in FIGLUI\n@mixin drop-shadow($size: 'md') {\n  @if ($size == sm) {\n    box-shadow: 0px 2px 3px 0px #00000040, 0px 0px 3px 0px #00000026;\n  } @else if ($size == lg) {\n    box-shadow: 0px 3px 12px 0px #00000026, 0px 12px 18px 4px #00000040;\n  } @else {\n    box-shadow: 0px 1px 6px 0px #00000026, 0px 6px 10px 0px #00000040;\n  }\n}\n","// This may be the case where and actual class is worthwhile\n\n@mixin ScreenReadersOnly {\n  position: absolute !important;\n  width: 1px !important;\n  height: 1px !important;\n  margin: 0 !important;\n  padding: 0 !important;\n  overflow: hidden !important;\n  clip: rect(0 0 0 0) !important;\n  -webkit-clip-path: inset(50%) !important;\n  clip-path: inset(50%) !important;\n  border: 0 !important;\n  white-space: nowrap !important;\n}\n",'@use "sass:math";\n\n@use "../../Foundation/Variables/ColorVars.scss" as colors;\n@use "../../Foundation/Variables/FontVars.scss" as fonts;\n@use "../../Foundation/Variables/MiscVars.scss" as misc;\n@use "../../Foundation/Variables/SpacingVars.scss" as spacing;\n@use "../../Foundation/Utilities" as *;\n\n// button variables only used for this file\n$strokeWeight: 1px;\n$reversed-btn-active-txt: rgba(255, 255, 255, 0.6);\n$reversed-no-bg-btn-active-txt: rgba(255, 255, 255, 0.8);\n$disabled-reversed-no-bg-btn-txt: rgba(255, 255, 255, 0.4);\n$btnLine-height: 24px;\n\n// reset buttons and base styling for all\n\n@mixin button {\n  @include fonts.font-bold();\n  font-size: 1rem;\n  line-height: $btnLine-height;\n  margin: 0;\n  padding: toRem(7px) spacing.$unit-xs * 2; //magic number to allow for 1px border to add to height\n  border: none;\n  border-radius: misc.$borderRadius;\n  transition: background-color 0.3s, color 0.3s, height 0.3s, border 0.3s,\n    fill 0.3s;\n\n  i,\n  svg * {\n    transition: color 0.3s, fill 0.3s;\n  }\n\n  &:hover {\n    cursor: pointer;\n  }\n}\n\nbutton {\n  @include button();\n}\n\n// create a SASS Mixin that can be called from the style definitions. You pass values and it will\n// pre-populate your style declaration with the content of the mixin.\n@mixin button-builder(\n  $btnTxtCol,\n  $btnBgCol,\n  $borderCol,\n  $myStrokeWeight: $strokeWeight,\n  $myBtnLineHeight: $btnLine-height\n) {\n  background-color: $btnBgCol;\n  border: $myStrokeWeight solid $borderCol;\n  color: $btnTxtCol;\n  line-height: $myBtnLineHeight;\n  font-weight: 600;\n\n  i,\n  svg * {\n    color: $btnTxtCol;\n    fill: $btnTxtCol;\n  }\n\n  &:visited {\n    color: $btnTxtCol;\n  }\n}\n\n// Broke the Button styling mixin into two so passing the values wouldn\'t be so overwelming.\n// This one defines the Hover and Active states of the button\n@mixin button-states-builder(\n  $btnTxtColHover,\n  $btnBgColHover,\n  $borderColHover,\n  $btnTxtColActive,\n  $btnBgColActive,\n  $borderColActive\n) {\n  &:hover {\n    background-color: $btnBgColHover;\n    cursor: pointer;\n    color: $btnTxtColHover;\n    border: $strokeWeight solid $borderColHover;\n\n    i,\n    svg * {\n      color: $btnTxtColHover;\n      fill: $btnTxtColHover;\n    }\n  }\n\n  &:disabled {\n    color: colors.$disabled-color;\n    background: colors.$disabled-bg-color;\n    border-color: colors.$disabled-color-dark;\n\n    i,\n    svg * {\n      color: colors.$disabled-color-dark;\n      fill: colors.$disabled-color-dark;\n    }\n\n    &:hover {\n      cursor: not-allowed;\n    }\n  }\n\n  &:active:enabled {\n    background-color: $btnBgColActive;\n    cursor: pointer;\n    color: rgba($btnTxtColActive, 0.9);\n    border: $strokeWeight solid $borderColActive;\n    //-moz-box-shadow: inset 0 3px 6px rgba(0, 0, 0, 0.2);\n    //-webkit-box-shadow: inset 0 3px 6px rgba(0, 0, 0, 0.2);\n    //box-shadow: inset 0 3px 6px rgba(0, 0, 0, 0.2);\n\n    i,\n    svg * {\n      color: $btnTxtColActive;\n      fill: $btnTxtColActive;\n    }\n  }\n}\n\na.lui-button {\n  @include button();\n  display: inline-block;\n  text-decoration: none;\n}\n\n.lui-button,\na.lui-button {\n  text-align: center;\n\n  &.lui-button-icon-right {\n    padding: spacing.$unit-xxs spacing.$unit-xs spacing.$unit-xs\n      spacing.$unit-sm; // magic numbers to account for border\n\n    .LuiIcon {\n      margin: 3px 0 -7px 12px; // magic numbers to allow the resize to work but to be fixed by future LUI buttons\n    }\n\n    i {\n      position: relative;\n      top: 6px;\n      margin: 0 0 0 12px;\n    }\n  }\n\n  &.lui-button-icon {\n    //padding: spacing.$unit-xxs spacing.$unit-xs*2 spacing.$unit-xs spacing.$unit-xs; // magic numbers to account for border\n    padding: toRem(7px) toRem(16px) toRem(7px) toRem(7px);\n\n    .LuiIcon {\n      margin: 0 8px -7px 0; // magic numbers to allow the resize to work but to be fixed by future LUI buttons\n    }\n\n    i {\n      position: relative;\n      top: 6px;\n      margin: 0 12px 0 0;\n    }\n  }\n\n  &-primary {\n    // var $btnTxtCol, $btnBgCol, $borderCol, $myStrokeWeight : 1px, $myBtnLineHeight : 22px\n    @include button-builder(#fff, colors.$sea, colors.$sea);\n    // var $btnTxtColHover, $btnBgColHover, $borderColHover, $btnTxtColActive, $btnBgColActive, $borderColActive\n    @include button-states-builder(\n      #fff,\n      colors.$primary-hover-btn,\n      colors.$primary-hover-btn,\n      $reversed-btn-active-txt,\n      colors.$primary-active-btn,\n      colors.$primary-active-btn\n    );\n  }\n\n  &-secondary {\n    // var $btnTxtCol, $btnBgCol, $borderCol, $myStrokeWeight : 2px, $myBtnLineHeight : 40px\n    @include button-builder(colors.$sea, #fff, colors.$sea);\n    // var $btnTxtColHover, $btnBgColHover, $borderColHover, $btnTxtColActive, $btnBgColActive, $borderColActive\n    @include button-states-builder(\n      colors.$sea,\n      colors.$secondary-hover-btn,\n      colors.$sea,\n      $reversed-btn-active-txt,\n      colors.$secondary-active-btn,\n      colors.$secondary-active-btn\n    );\n\n    i,\n    svg * {\n      color: colors.$sea;\n    }\n\n    &:hover i {\n      color: colors.$sea;\n    }\n  }\n\n  &-tertiary {\n    @include button-builder(\n      colors.$sea,\n      transparent,\n      transparent,\n      0px,\n      $btnLine-height - 2px\n    );\n    @include button-states-builder(\n      colors.$sea,\n      colors.$tertiary-hover-btn,\n      #fff,\n      $reversed-btn-active-txt,\n      colors.$tertiary-active-btn,\n      #fff\n    );\n    @include fonts.font-regular();\n\n    border: none;\n    margin: 2px; //account for the slightly smaller button size;\n\n    &:hover {\n      border: none;\n    }\n\n    &:active:enabled {\n      border: none;\n    }\n\n    &:disabled {\n      color: colors.$disabled-color;\n      background: none;\n      text-decoration: none;\n      border: none;\n\n      &:hover {\n        cursor: not-allowed;\n        border: none;\n      }\n\n      i,\n      svg * {\n        color: colors.$gray;\n        fill: colors.$gray;\n      }\n    }\n  }\n\n  &-success {\n    // var $btnTxtCol, $btnBgCol, $borderCol, $myStrokeWeight : 2px, $myBtnLineHeight : 40px\n    @include button-builder(#fff, colors.$green-btn, colors.$green-btn);\n    // var $btnTxtColHover, $btnBgColHover, $borderColHover, $btnTxtColActive, $btnBgColActive, $borderColActive\n    @include button-states-builder(\n      #fff,\n      colors.$green-hover,\n      colors.$green-hover,\n      $reversed-btn-active-txt,\n      colors.$green-active,\n      colors.$green-active\n    );\n  }\n\n  &-error {\n    // var $btnTxtCol, $btnBgCol, $borderCol, $myStrokeWeight : 2px, $myBtnLineHeight : 40px\n    @include button-builder(#fff, colors.$error, colors.$error);\n    // var $btnTxtColHover, $btnBgColHover, $borderColHover, $btnTxtColActive, $btnBgColActive, $borderColActive\n    @include button-states-builder(\n      #fff,\n      colors.$error-hover-btn,\n      colors.$error-hover-btn,\n      $reversed-btn-active-txt,\n      colors.$error-active-btn,\n      colors.$error-active-btn\n    );\n  }\n\n  &-reversed-no-bg {\n    // var $btnTxtCol, $btnBgCol, $borderCol, $myStrokeWeight : 2px, $myBtnLineHeight : 40px\n    @include button-builder(#fff, transparent, transparent);\n    // var $btnTxtColHover, $btnBgColHover, $borderColHover, $btnTxtColActive, $btnBgColActive, $borderColActive\n    @include button-states-builder(\n      $reversed-no-bg-btn-active-txt,\n      transparent,\n      transparent,\n      $reversed-btn-active-txt,\n      transparent,\n      transparent\n    );\n\n    i {\n      font-size: 2.5rem;\n      top: 13px !important; // overwrite the base btn icon positioning without reworking mulitple classes\n    }\n\n    &:disabled {\n      color: $disabled-reversed-no-bg-btn-txt;\n      background: none;\n      border: 0;\n\n      i,\n      svg * {\n        color: $disabled-reversed-no-bg-btn-txt;\n        fill: $disabled-reversed-no-bg-btn-txt;\n      }\n\n      &:hover {\n        cursor: not-allowed;\n      }\n    }\n  }\n\n  &-text {\n    // var $btnTxtCol, $btnBgCol, $borderCol, $myStrokeWeight : 2px, $myBtnLineHeight : 40px\n    @include button-builder(colors.$txt-link, transparent, #fff, 0, 24px);\n    // var $btnTxtColHover, $btnBgColHover, $borderColHover, $btnTxtColActive, $btnBgColActive, $borderColActive\n    @include button-states-builder(\n      colors.$teal,\n      transparent,\n      none,\n      colors.$teal,\n      none,\n      none\n    );\n    // border bottom mimics what we have for text link styling\n    //border-bottom: 1px solid;\n    text-decoration: underline;\n    @include fonts.font-regular();\n    // remove the padding and margin off the buttons - used for text only buttons\n    padding: 0;\n    margin: 0;\n    border-radius: 0; // remove border radius so the text underline via border bottom doesn\'t turn up at the ends\n    //&:hover {\n    //  border-bottom: 1px solid;\n    //}\n    &:active:enabled {\n      background-color: #fff;\n      cursor: pointer;\n      //color: rgba($btnTxtColActive, 0.9);\n      //border: $strokeWeight solid $borderColActive;\n      -moz-box-shadow: none;\n      -webkit-box-shadow: none;\n      box-shadow: none;\n\n      i,\n      svg * {\n        color: #fff;\n        fill: #fff;\n      }\n    }\n\n    &:disabled {\n      color: colors.$disabled-color;\n      background: none;\n      //border: 0;\n      text-decoration: underline;\n\n      &:hover {\n        cursor: not-allowed;\n      }\n\n      i,\n      svg * {\n        color: colors.$gray;\n        fill: colors.$gray;\n      }\n    }\n  }\n\n  &-plain-text {\n    // var $btnTxtCol, $btnBgCol, $borderCol\n    @include button-builder(inherit, transparent, #fff, 0);\n    // remove the padding and margin off the buttons - used for text only buttons\n    padding: 0;\n    margin: 0;\n    font-family: inherit;\n    font-size: inherit;\n    line-height: inherit;\n    color: inherit;\n    font-weight: inherit;\n\n    i,\n    svg * {\n      color: colors.$fuscous;\n      fill: colors.$fuscous;\n    }\n\n    &:disabled {\n      color: colors.$disabled-color;\n      background: none;\n      border: 0;\n      text-decoration: none;\n      &:hover {\n        cursor: not-allowed;\n      }\n\n      i,\n      svg * {\n        color: colors.$disabled-color;\n        fill: colors.$disabled-color;\n      }\n    }\n  }\n\n  &-icon-only {\n    width: 40px;\n    height: 40px;\n    padding: 0;\n\n    .LuiIcon {\n      vertical-align: top; //not sure why top makes the icon align in the center\n    }\n\n    i {\n      position: relative;\n      top: 6px;\n      margin: 0 12px 0 0;\n    }\n  }\n\n  &-icon-only-rev,\n  &-icon-only-link {\n    // var $btnTxtCol, $btnBgCol, $borderCol, $myStrokeWeight : 2px, $myBtnLineHeight : 40px\n    @include button-builder(colors.$sea, transparent, transparent);\n    // var $btnTxtColHover, $btnBgColHover, $borderColHover, $btnTxtColActive, $btnBgColActive, $borderColActive\n    @include button-states-builder(\n      colors.$primary-hover-btn,\n      transparent,\n      transparent,\n      colors.$txt-link,\n      transparent,\n      transparent\n    );\n    // OK, for some reason setting the line height to 44px sets the icon in the centre of the 36 X 36 box. Tested fine on Chrome, FF & Safari\n    line-height: 44px;\n    padding: 0;\n    width: 36px;\n    height: 36px;\n\n    &:disabled {\n      background-color: transparent;\n      border: 0;\n    }\n  }\n\n  &-icon-only-rev {\n    color: #fff;\n\n    i,\n    svg * {\n      color: #fff;\n    }\n    &:disabled,\n    &:disabled:hover {\n      color: $disabled-reversed-no-bg-btn-txt;\n\n      i,\n      svg * {\n        color: $disabled-reversed-no-bg-btn-txt;\n        fill: $disabled-reversed-no-bg-btn-txt;\n      }\n    }\n    &:hover {\n      i,\n      svg * {\n        color: colors.$spray;\n        fill: colors.$spray;\n      }\n    }\n  }\n\n  &-icon-only-link {\n    color: colors.$txt-link;\n  }\n\n  &.lui-button-sm {\n    padding: toRem(3px) spacing.$unit-xs;\n\n    &.lui-button-text {\n      padding: 0;\n    }\n\n    &.lui-button-plain-text {\n      padding: 0;\n    }\n\n    &.lui-button-icon {\n      padding: toRem(2px) toRem(8px) toRem(2px) spacing.$unit-xxs;\n\n      .LuiIcon {\n        margin: 1px 4px -5px 0; // magic numbers to allow the resize to work but to be fixed by future LUI buttons\n      }\n\n      i {\n        position: relative;\n        top: 6px;\n        margin: 0 12px 0 0;\n      }\n    }\n\n    &.lui-button-icon-only {\n      width: 32px;\n      height: 32px;\n      padding: 0;\n\n      .LuiIcon {\n        vertical-align: top;\n      }\n\n      i {\n        position: relative;\n        top: 6px;\n        margin: 0 12px 0 0;\n      }\n    }\n\n    &.lui-button-icon-right {\n      padding: toRem(2px) spacing.$unit-xxs toRem(2px) toRem(8px);\n\n      .LuiIcon {\n        margin: 1px 0 -5px toRem(4px); // magic numbers to allow the resize to work but to be fixed by future LUI buttons\n      }\n\n      i {\n        position: relative;\n        top: 6px;\n        margin: 0 0 0 12px;\n      }\n    }\n\n    &.lui-button-reversed-no-bg {\n      i,\n      .LuiIcon {\n        // font-size: 1.8rem;\n        top: 9px !important;\n      }\n    }\n  }\n\n  // medium is not defined as that is the default button size\n  &.lui-button-lg {\n    padding: toRem(11px) toRem(18px); // magic numbers to account for border\n\n    &.lui-button-text {\n      padding: 0;\n    }\n\n    &.lui-button-plain-text {\n      padding: 0;\n    }\n\n    &.lui-button-icon {\n      padding: toRem(11px) 16px toRem(11px) spacing.$unit-sm; // magic numbers to account for border\n\n      i {\n        position: relative;\n        top: 6px;\n        margin: 0 toRem(8px) 0 0;\n      }\n    }\n\n    &.lui-button-icon-only {\n      width: 48px;\n      height: 48px;\n      padding: 0; // magic numbers to account for border\n\n      .LuiIcon {\n        vertical-align: top;\n      }\n\n      i {\n        position: relative;\n        top: 6px;\n        margin: 0 toRem(8px) 0 0;\n      }\n    }\n\n    &.lui-button-icon-right {\n      padding: toRem(11px) spacing.$unit-sm toRem(11px) spacing.$px; // magic numbers to account for border\n\n      i {\n        position: relative;\n        top: 6px;\n        margin: 0 0 0 toRem(8px);\n      }\n    }\n  }\n\n  // If the buttons appear next to each other, then add a margin\n  + .lui-button {\n    margin-left: spacing.$unit-xs;\n  }\n\n  + a.lui-button {\n    margin-left: spacing.$unit-xs;\n  }\n}\n\n.lui-button-group {\n  display: flex; // Whitespace was appearing between buttons, this fixes it\n  align-content: stretch; //fill the horiztonal space on mobile\n  flex-direction: row;\n\n  .lui-button-wrapper {\n    flex: 1 1 0;\n\n    &:first-child button {\n      border-left: 1px solid colors.$brand-primary;\n      border-top-left-radius: misc.$borderRadius;\n      border-bottom-left-radius: misc.$borderRadius;\n    }\n\n    &:last-child button {\n      border-top-right-radius: misc.$borderRadius;\n      border-bottom-right-radius: misc.$borderRadius;\n    }\n  }\n\n  &.lui-input-error {\n    border-radius: misc.$borderRadius * 1.5; // Makes the outter border hug the inner border and avoids white space\n    // Other error styling is inherited from checkbox & radio groups, so head over there for declarations\n  }\n\n  &-text-sizing {\n    //remove flexbox so they can just be inline buttons. Flexbox wasn\'t allowing the buttons to be sized by their content (flex shrink made a mess of things)\n    display: inline-block;\n    font-size: 0;\n\n    .lui-button-wrapper {\n      width: auto;\n      float: left; // have gone for floating blocks, as inline-blocks had white space and the usual CSS tricks like font-size: 0 didn\'t work. So done it the old school way\n      .lui-button {\n        @include breakpoint(md) {\n          padding: 0 spacing.$unit-sm;\n        }\n        @include breakpoint(lg) {\n          padding: 0 spacing.$unit-lg;\n        }\n      }\n    }\n  }\n\n  .lui-button {\n    background-color: #fff;\n    border-radius: 0;\n    border: 1px solid colors.$sea;\n    color: colors.$brand-primary;\n    border-left: none;\n    width: 100%;\n    svg * {\n      fill: colors.$sea;\n    }\n\n    &.lui-button-active {\n      background-color: colors.$sea;\n      -moz-box-shadow: inset 0 3px 6px rgba(0, 0, 0, 0.4);\n      -webkit-box-shadow: inset 0 3px 6px rgba(0, 0, 0, 0.4);\n      box-shadow: inset 0 3px 6px rgba(0, 0, 0, 0.4);\n      color: colors.$white;\n      text-shadow: 0 3px 6px rgba(0, 0, 0, 0.4);\n      svg * {\n        fill: colors.$white;\n      }\n      //style selected button when disabled\n      &:disabled {\n        background-color: colors.$disabled-color;\n        color: colors.$white;\n        &.lui-button-icon-only svg * {\n          fill: colors.$white;\n        }\n      }\n    }\n\n    &:hover {\n      background: colors.$sea;\n      cursor: pointer;\n      color: colors.$white;\n    }\n\n    &:focus {\n      outline: 2px solid colors.$brand-primary;\n      // make sure the button sits above the others so the outline is not cut off on focus\n      position: relative;\n    }\n    &:disabled {\n      background-color: colors.$disabled-bg-color;\n      border: 1px solid colors.$disabled-color-dark;\n      color: colors.$disabled-color;\n      cursor: not-allowed;\n      &.lui-button-icon-only svg * {\n        fill: colors.$disabled-color;\n      }\n    }\n    &.lui-button-icon-only {\n      // if using icon only buttons, then don\'t restrict their width\n      width: 100%;\n    }\n  }\n\n  &--radio {\n    margin-top: spacing.$unit-md;\n\n    .lui-radio-container {\n      margin-top: spacing.$unit-sm; // 12px\n    }\n\n    @include breakpoint(md) {\n      .LuiDeprecatedForms & {\n        display: grid;\n      }\n\n      // add a 24 column grid so you have more control over the size of the buttons at various breakpoints\n      display: grid;\n      grid-template-columns: repeat(24, 1fr);\n      // Set the font size to 0 so no spaces appear between the labels\n      font-size: 0 !important;\n\n      input {\n        // hide the input from view, but not from screenreaders to ensure the element can still get focus when tabbing through\n        @include ScreenReadersOnly();\n\n        &:checked + label {\n          background-color: colors.$sea;\n          box-shadow: inset 0 2px 3px rgba(0, 0, 0, 0.5);\n          color: colors.$white;\n          text-shadow: 0 2px 3px rgba(0, 0, 0, 0.5);\n\n          .LuiDeprecatedForms & {\n            color: colors.$white;\n          }\n        }\n\n        &:checked:disabled + label,\n        &:disabled:checked + label:hover {\n          background-color: colors.$gray;\n          color: colors.$white;\n\n          .LuiDeprecatedForms & {\n            color: colors.$white;\n          }\n        }\n\n        &:focus:not([disabled]) + label {\n          color: colors.$white;\n          background: colors.$sea;\n          cursor: pointer;\n        }\n\n        &:disabled + label {\n          border-color: colors.$gray !important; // imp! for overwrite RH border styling\n        }\n\n        &:disabled + label:hover {\n          background-color: colors.$white;\n          cursor: default;\n        }\n      }\n    }\n\n    label {\n      margin-left: spacing.$unit-xs; // 8px\n      // label to look like buttons on larger screens\n      @include breakpoint(md) {\n        display: inline-block;\n        // copied Lui button styles based on secondary button styling\n        //@include fonts.font-bold;\n        // Messy override to prevent the bold font from being overridden by the normal radio label styles\n        font-family: fonts.$base-font--combined;\n        font-weight: 700 !important;\n        line-height: 40px;\n        transition: background-color 0.3s, color 0.3s, height 0.3s, border 0.3s;\n        text-align: center;\n        border: 2px solid colors.$sea;\n        color: colors.$sea;\n        border-radius: 0;\n        border-right: none;\n        width: 100%;\n        margin: 0;\n\n        &:hover {\n          color: colors.$white;\n          background: colors.$sea;\n          cursor: pointer;\n        }\n      }\n    }\n  }\n}\n\n.LuiDeprecatedForms {\n  .radio-btn-group-pair {\n    // add a 24 column grid so you have more control over the size of the buttons at various breakpoints\n    display: grid;\n    grid-template-columns: repeat(24, 1fr);\n    // Set the font size to 0 so no spaces appear between the labels\n    font-size: 0 !important;\n\n    input {\n      // hide the input from view, but not from screenreaders to ensure the element can still get focus when tabbing through\n      @include ScreenReadersOnly();\n\n      &:checked + label {\n        background-color: colors.$sea;\n        box-shadow: inset 0 2px 3px rgba(0, 0, 0, 0.5);\n        color: colors.$white;\n        text-shadow: 0 2px 3px rgba(0, 0, 0, 0.5);\n      }\n\n      &:focus + label {\n        color: colors.$white;\n        background: colors.$sea;\n        cursor: pointer;\n      }\n    }\n\n    label {\n      // label to look like buttons on larger screens\n      display: inline-block;\n      // copied Lui button styles based on secondary button styling\n      @include fonts.font-bold;\n      line-height: 40px;\n      transition: background-color 0.3s, color 0.3s, height 0.3s, border 0.3s;\n      text-align: center;\n      border: 2px solid colors.$sea;\n      color: colors.$sea;\n      border-radius: 0;\n      border-right: none;\n      width: 100%;\n      margin: 0;\n\n      &:hover {\n        color: colors.$white;\n        background: colors.$sea;\n        cursor: pointer;\n      }\n    }\n\n    .grid-cell-1 {\n      grid-column: span 12;\n\n      label {\n        border-radius: spacing.$unit-xs 0 0 spacing.$unit-xs;\n      }\n    }\n\n    .grid-cell-2 {\n      grid-column: span 12;\n\n      label {\n        border-right: 2px solid colors.$sea;\n        border-radius: 0 spacing.$unit-xs spacing.$unit-xs 0;\n      }\n    }\n\n    @include breakpoint(md) {\n      .grid-cell-1 {\n        grid-column: span 6;\n      }\n\n      .grid-cell-2 {\n        grid-column: span 6;\n      }\n    }\n    @include breakpoint(lg) {\n      .grid-cell-1 {\n        grid-column: span 5;\n      }\n\n      .grid-cell-2 {\n        grid-column: span 5;\n      }\n    }\n    @include breakpoint(xl) {\n      .grid-cell-1 {\n        grid-column: span 4;\n      }\n\n      .grid-cell-2 {\n        grid-column: span 4;\n      }\n    }\n  }\n}\n\n.exampleOfGridForButtons {\n  @include breakpoint(md) {\n    .grid-cell-1 {\n      grid-column: span 3;\n\n      label {\n        border-radius: spacing.$unit-xs 0 0 spacing.$unit-xs;\n      }\n    }\n\n    .grid-cell-2 {\n      grid-column: span 5;\n    }\n\n    .grid-cell-3 {\n      grid-column: span 8;\n    }\n\n    .grid-cell-4 {\n      grid-column: span 8;\n\n      label {\n        border-right: 2px solid colors.$sea;\n        border-radius: 0 spacing.$unit-xs spacing.$unit-xs 0;\n      }\n    }\n  }\n  @include breakpoint(lg) {\n    .grid-cell-1 {\n      grid-column: span 4;\n    }\n\n    .grid-cell-2 {\n      grid-column: span 5;\n    }\n\n    .grid-cell-3 {\n      grid-column: span 5;\n    }\n\n    .grid-cell-4 {\n      grid-column: span 5;\n    }\n  }\n  @include breakpoint(xl) {\n    .grid-cell-1 {\n      grid-column: span 3;\n    }\n\n    .grid-cell-2 {\n      grid-column: span 4;\n    }\n\n    .grid-cell-3 {\n      grid-column: span 4;\n    }\n\n    .grid-cell-4 {\n      grid-column: span 4;\n    }\n  }\n}\n',"@use './ColorVars.scss' as colors;\n\n///////////////////////////////////////\n// Misc Variables\n///////////////////////////////////////\n\n// This file is for holding global variables that don't neatly fall under a specific category\n\n// ============\n// Z-indices\n// ============\n$z-0: 0;\n$z-10: 10;\n$z-20: 20;\n$z-30: 30;\n$z-40: 40;\n$z-50: 50;\n\n// Border radius\n$borderRadius: 3px;\n\n// These are to provide more flexibility\n$borderRadius-sm: $borderRadius;\n$borderRadius-md: 5px;\n$borderRadius-lg: 9px;\n",'@use "./buttons.scss";\n@use "../../Foundation/Variables/ColorVars.scss" as colors;\n\n.linz-button-primary {\n  border: buttons.$strokeWeight solid colors.$linz-color-primary;\n  background-color: colors.$linz-color-primary;\n  border-color: colors.$linz-color-primary;\n  color: #fff;\n  &:hover {\n    background-color: colors.$linz-color-primary-hover;\n    border-color: colors.$linz-color-primary-hover;\n    cursor: pointer;\n  }\n}\n\n.linz-button-secondary {\n  border: buttons.$strokeWeight solid colors.$linz-color-primary;\n  color: colors.$linz-color-primary;\n  &:hover {\n    background-color: colors.$linz-color-primary-hover;\n    border-color: colors.$linz-color-primary-hover;\n    color: #fff;\n    cursor: pointer;\n  }\n}\n\n.linz-button-tertiary {\n  border: buttons.$strokeWeight solid colors.$linz-color-tertiary;\n  background-color: colors.$linz-color-tertiary;\n  color: colors.$linz-color-primary;\n  &:hover {\n    background-color: colors.$linz-color-tertiary-hover;\n    border-color: colors.$linz-color-tertiary-hover;\n    cursor: pointer;\n  }\n}\n',"@use \"../../../Foundation/Variables/ColorVars.scss\" as colors;\n@use \"../../../Foundation/Variables/MiscVars.scss\" as misc;\n@use \"../../../Foundation/Variables/FontVars.scss\" as fonts;\n@use \"../../../Foundation/Variables/FormVars.scss\" as forms;\n@use \"../../../Foundation/Utilities/\" as *;\n\n// All this is now legacy, deprecated styling.\n// In order to access these styles, use a wrapping div with the class LuiDeprecatedForms as close to the desired form/elements as possible\n// There will be global styles that these will override so make sure you're scoping the wrapper really close to avoid unexpected behaviour\n\n// START inputs, textareas and select base styling - excludes checkboxes and radios\n\n@mixin inputs(\n  $my-font-size,\n  $my-line-height,\n  $my-label-font-size,\n  $my-padding,\n  $my-lui-form-error-icon-size,\n  $my-lui-error-icon-pos,\n  $my-input-height\n) {\n  input:not([type='checkbox']):not([type='radio']),\n  textarea,\n  select {\n    @include fonts.font-regular;\n    font-size: $my-font-size;\n    color: colors.$input-text;\n    border: forms.$input-border-width solid colors.$silver;\n    border-radius: misc.$borderRadius;\n    line-height: $my-input-height;\n    width: 100%;\n    margin: 0;\n    transition: border 0.3s ease(in-out-expo);\n    box-sizing: border-box;\n    min-height: $my-input-height;\n\n    &::placeholder {\n      @include fonts.font-italic;\n      color: colors.$input-placeholder;\n    }\n  }\n\n  textarea {\n    @include fonts.font-regular; // for textarea input\n    line-height: fonts.$base-line-height;\n    padding: 0.5rem 0.5rem 0.5rem 0.75rem;\n  }\n\n  select {\n    @include appearance(none);\n    @include fonts.font-regular;\n    cursor: pointer;\n    -webkit-font-smoothing: antialiased;\n    -moz-osx-font-smoothing: grayscale;\n    background-repeat: no-repeat;\n    background-position: right 0.7em top 50%;\n    background-size: 1.5rem auto;\n    // use url-encode-decode.com to decode the below SVG for any changes\n    background-image: url('data:image/svg+xml,%3C%3Fxml%20version%3D%221.0%22%20encoding%3D%22utf-8%22%3F%3E%0A%20%3Csvg%20version%3D%221.1%22%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%2224%22%20height%3D%2224%22%20viewBox%3D%220%200%2024%2024%22%3E%0A%20%3Cpath%20d%3D%22M7%2010l5%205%205-5z%22%20fill%3D%22%23414042%22%20%2F%3E%20%0A%20%3C%2Fsvg%3E');\n  }\n\n  input:not([type='checkbox']):not([type='radio']),\n  select {\n    padding: 0 0.75rem;\n  }\n\n  .lui-input-error {\n    position: relative;\n\n    .lui-form-status-icon {\n      position: absolute;\n      top: $my-lui-error-icon-pos;\n      left: $my-lui-error-icon-pos;\n      color: white;\n      z-index: 1;\n      font-size: $my-lui-form-error-icon-size;\n    }\n    // Style all inputs but checkboxes and radio's. They are styled as a group\n    input:not([type='checkbox']):not([type='radio']),\n    textarea,\n    select {\n      border: forms.$input-border-width solid colors.$error;\n      border-left: $my-line-height solid colors.$error;\n      @include box-shadow;\n      &:focus {\n        outline: forms.$input-border-width solid colors.$error-focus;\n      }\n    }\n\n    p {\n      font-size: $my-label-font-size;\n    }\n  }\n\n  .lui-input-warning {\n    position: relative;\n\n    .lui-form-status-icon {\n      position: absolute;\n      top: $my-lui-error-icon-pos;\n      left: $my-lui-error-icon-pos;\n      color: white;\n      z-index: 100;\n      font-size: $my-lui-form-error-icon-size;\n    }\n    // Style all inputs but checkboxes and radio's. They are styled as a group\n    input:not([type='checkbox']):not([type='radio']),\n    textarea,\n    select {\n      border: forms.$input-border-width solid colors.$warning;\n      border-left: $my-line-height solid colors.$warning;\n      @include box-shadow;\n      &:focus {\n        outline: forms.$input-border-width solid colors.$warning-focus;\n      }\n    }\n\n    p {\n      font-size: $my-label-font-size;\n    }\n  }\n\n  label,\n  fieldset,\n  legend {\n    display: block;\n  }\n\n  label,\n  legend {\n    font-size: $my-label-font-size;\n    @include fonts.font-semibold;\n  }\n\n  fieldset {\n    border: none;\n    padding: 0;\n  }\n\n  .lui-required-input-icon {\n    display: inline-block;\n    width: 10px;\n    margin: 0 0 0 -10px;\n    color: colors.$error;\n    @include fonts.font-semibold();\n    @include breakpoint(md) {\n      margin: 0 5px 0 -15px;\n    }\n  }\n\n  .lui-error-msg {\n    @include fonts.font-semibold;\n    color: colors.$error;\n  }\n\n  .lui-bearing-input-wrapper {\n    max-width: 750px;\n    position: relative;\n\n    .lui-bearing-display {\n      position: absolute;\n      right: 14px;\n      top: 0;\n      line-height: $my-line-height;\n      color: colors.$silver;\n    }\n  }\n}\n\n.LuiDeprecatedForms {\n  .LuiFormLabel-wrapper {\n    margin-bottom: 4px;\n  }\n}\n",'@use "../../../Foundation/Variables/ColorVars.scss" as colors;\n@use "../../../Foundation/Variables/FontVars.scss" as fonts;\n@use "../../../Foundation/Variables/MiscVars.scss" as misc;\n@use "../../../Foundation/Variables/SpacingVars.scss" as spacing;\n@use "../../../Foundation/Variables/FormVars.scss" as forms;\n@use "../../../Foundation/Utilities/" as *;\n\n// All this is now legacy, deprecated styling.\n// In order to access these styles, use a wrapping div with the class LuiDeprecatedForms as close to the desired form/elements as possible\n// There will be global styles that these will override so make sure you\'re scoping the wrapper really close to avoid unexpected behaviour\n\n.LuiDeprecatedForms {\n  .lui-checkbox-container,\n  .lui-radio-container {\n    display: flex;\n    position: relative;\n\n    input {\n      height: forms.$input-width;\n      // min width was added as the checkbox width was being influenced by the width of the container and a cropping effect occurred\n      min-width: forms.$input-width;\n      width: forms.$input-width;\n      @include appearance(none);\n      border: forms.$input-border-width-thick solid\n        forms.$checkbox-border-colour;\n      background-color: colors.$white;\n      position: relative;\n      margin: 0;\n      &:disabled {\n        border: forms.$input-border-width solid colors.$gray;\n        background-color: colors.$lily;\n        + label {\n          color: colors.$disabled-color;\n        }\n      }\n    }\n\n    label {\n      @include fonts.font-light();\n      font-size: fonts.$base-font-size;\n    }\n  }\n\n  .lui-radio-container {\n    input {\n      border-radius: 50%;\n      &:checked {\n        &:before {\n          display: block;\n          position: absolute;\n          left: 50%;\n          content: \'\';\n          top: 50%;\n          transform: translate(-50%, -50%);\n          width: 14px;\n          height: 14px;\n          border-radius: 50%;\n          background: colors.$brand-primary;\n        }\n        &:disabled:before {\n          background: colors.$disabled-color-dark;\n        }\n      }\n    }\n  }\n\n  .lui-checkbox-container {\n    input[type=\'checkbox\'] {\n      box-sizing: border-box;\n      border-radius: misc.$borderRadius;\n      position: relative;\n      &:checked {\n        border: forms.$input-border-width-thick solid colors.$brand-primary;\n        background-color: colors.$brand-primary;\n        &:before {\n          display: block;\n          position: absolute;\n          width: forms.$input-width -\n            (forms.$input-border-width-thick + forms.$input-border-width-thick);\n          height: forms.$input-width -\n            (forms.$input-border-width-thick + forms.$input-border-width-thick);\n          font-family: \'Material Icons Round\';\n          left: 0;\n          top: -1px;\n          content: \'\\e876\';\n          text-align: center;\n          color: #fff;\n          font-size: forms.$checkbox-icon-font-size;\n          line-height: forms.$checkbox-icon-line-height;\n        }\n        &:disabled {\n          background: colors.$disabled-color-dark;\n          border-color: colors.$disabled-color-dark;\n        }\n      }\n    }\n  }\n\n  .lui-input-error {\n    // Checkboxes and radio groups are styled differently in error states. The error styling wraps around the whole group\n    .lui-input-group-wrapper,\n    &.lui-button-group {\n      // Button groups are styled the same as checkbox/radio groups, except for the padding\n      position: relative;\n      border: forms.$input-border-width solid colors.$error;\n      border-left: 48px solid colors.$error;\n      padding: spacing.$unit-xxs spacing.$unit-xs spacing.$unit-xs;\n      margin-top: spacing.$unit-md;\n      @include box-shadow;\n      .lui-form-status-icon {\n        left: spacing.$base-unit * -5;\n        font-size: forms.$form-error-icon-size;\n      }\n    }\n    &.lui-button-group {\n      padding: 0;\n      .lui-button-wrapper button {\n        border: forms.$input-border-width solid colors.$error;\n      }\n    }\n  }\n}\n',"// ============\n// Appearance\n// ============\n\n//   🤔 don't think we need this - seems highly specific\n\n@mixin appearance($value) {\n  appearance: $value;\n  -webkit-appearance: $value;\n  -moz-appearance: $value;\n  -o-appearance: $value;\n}\n","@use \"sass:math\";\n\n@use './SpacingVars.scss' as spacing;\n@use './ColorVars.scss' as colors;\n@use './FontVars.scss' as fonts;\n@use '../Utilities/REM.scss' as rem;\n\n$label-spacing: spacing.$unit-md; // 24px\n$input-spacing: spacing.$unit-xs; // 8px\n\n$label-font-size: rem.toRem(14px);\n$label-line-height: spacing.$unit-md;\n\n@mixin formLabel {\n  @include fonts.font-semibold();\n  margin-bottom: $input-spacing;\n  font-size: $label-font-size;\n  line-height: $label-line-height;\n  color: colors.$charcoal;\n}\n\n@mixin formPlaceholder {\n  &::placeholder {\n    font-weight: normal;\n    font-style: italic;\n    color: colors.$input-placeholder;\n    opacity: 1; // Because firefox is cool\n\n    .isDisabled & {\n      color: colors.$input-placeholder-when-disabled;\n    }\n  }\n}\n\n$input-width: spacing.$unit-md;\n$input-border-width: 0.06rem; // 1px\n$input-border-width-thick: 0.13rem; // 2px\n\n$checkbox-icon-font-size: 1.13rem; // 18px\n$checkbox-icon-line-height: spacing.$unit-md; // 24px\n$checkbox-label-spacing: $input-spacing;\n$checkbox-border-colour: colors.$sea;\n\n$form-error-icon-size: spacing.$unit-lg;\n",'@use \'../../Elements/Forms/FormComponents/Inputs.scss\' as Inputs;\n@use \'../../Elements/Forms/FormComponents/RadiosCheckboxes.scss\' as RadiosCheckboxes;\n@use \'../../Elements/Forms/FormComponents/FormSpacing.scss\' as FormSpacing;\n@use "../../Foundation/Variables/FontVars.scss" as fonts;\n@use "../../Foundation/Variables/SpacingVars.scss" as spacing;\n@use "../../Foundation/Variables/ColorVars.scss" as colors;\n@use "../../Foundation/Variables/FormVars.scss" as forms;\n@use "../../Foundation/Utilities/" as *;\n\n// All this is now legacy, deprecated styling.\n// In order to access these styles, use a wrapping div with the class LuiDeprecatedForms as close to the desired form/elements as possible\n// There will be global styles that these will override so make sure you\'re scoping the wrapper really close to avoid unexpected behaviour\n.LuiDeprecatedForms {\n  // -------------------------------------------------------------------------------------------------------------------------------------\n  // ---- Lui Form has inputs/form elements with all the styling, but no margins set\n  // -------------------------------------------------------------------------------------------------------------------------------------\n\n  @include Inputs.inputs(\n    // The font size\n    fonts.$base-font-size,\n    // The line height\n    48px,\n    // The size of the font for the label\n    toRem(14px),\n    // The padding on the input\n    spacing.$unit-xs,\n    // The size of the icon for the warning/error (may change if we have a compressed version of forms)\n    forms.$form-error-icon-size,\n    // The offset positioning of the error icon\n    spacing.$base-unit,\n    // the input height\n    48px\n  );\n\n  @include FormSpacing.form-spacing(\n    // top margin for labels that aren\'t for checkboxes or radio\n    forms.$label-spacing,\n    // top offset for radio and checkbox inputs\n    forms.$input-spacing,\n    // top margin for radio and checkboxes\n    forms.$input-spacing,\n    // top margin for the container of radio or checkbox group\n    forms.$input-spacing,\n    // Error message top margin\n    0.5rem,\n    // Top margin on error text that appears next to inputs\n    5px,\n    // mobile option for top margin for labels that aren\'t for checkboxes or radio\n    forms.$label-spacing\n  );\n}\n',"@use \"../../../Foundation/Variables/MiscVars.scss\" as misc;\n\n@mixin form-spacing(\n  // top margin for labels that aren't for checkboxes or radio\n  $my-label-top-margin,\n  // top offset for radio and checkbox inputs\n  $my-checkbox-input-top-offset,\n  // top margin for radio and checkboxes\n  $my-checkbox-margin-top,\n  // top margin for the container of radio or checkbox group\n  $my-input-wrapper-spacing,\n  // Error message top margin\n  $my-error-msg-top-margin,\n  // Top margin on error text that appears next to inputs\n  $my-lui-error-text-top-margin,\n  // mobile option for top margin for labels that aren't for checkboxes or radio\n  $my-label-top-margin-mob: $my-label-top-margin\n) {\n  // All the margin declarations\n  // ------------------------------------------------------------------------------------------------\n  .lui-input-group-wrapper {\n    margin-top: $my-input-wrapper-spacing;\n  }\n\n  p.lui-fieldset-support-txt {\n    margin-top: $my-error-msg-top-margin;\n  }\n\n  .lui-error-msg {\n    margin-top: $my-lui-error-text-top-margin;\n  }\n}\n","// Things that are common to all inputs\nfieldset {\n  // reset browser stylesheet\n  border: none;\n  padding: 0;\n  margin-inline-start: 0;\n  margin-inline-end: 0;\n}\n",'@use "../../Foundation/Utilities" as *;\n@use "../../Foundation/Variables/ColorVars.scss" as colors;\n\n.lui-icon {\n  display: inline-block;\n  width: 24px;\n  height: 24px;\n\n  &-lg {\n    width: 48px;\n    height: 48px;\n    font-size: 3rem;\n  }\n  &-maori-land {\n    //background: url(../assets/icons/lui-icon-maori-land.svg) no-repeat center;\n    background-size: cover;\n  }\n}\n\n//Target all i tags that have material icon class names\n//button icons are styled within the button scss\n// Icons within text links are handled in the type.scss file\n*:not[button] {\n  i[class^=\'material-icons\'],\n  .lui-link-icon {\n    color: colors.$base-icon-color;\n    transition: color 0.3s ease(in-out-expo);\n\n    &:hover {\n      cursor: pointer;\n      color: colors.$brand-primary;\n    }\n    &:visited {\n      color: colors.$visited;\n    }\n  }\n\n  .lui-link-icon-disabled {\n    i {\n      color: colors.$disabled-color;\n      &:hover {\n        cursor: not-allowed;\n      }\n    }\n  }\n}\n\n.lui-inactive-icon {\n  color: colors.$gray;\n}\n','@use "sass:math";\n\n@use "../../Foundation/Variables/MiscVars.scss" as misc;\n@use "../../Foundation/Variables/ColorVars.scss" as colors;\n@use "../../Foundation/Variables/FontVars.scss" as fonts;\n@use "../../Foundation/Variables/SpacingVars.scss" as spacing;\n\n$icon-col-width: math.div(24, 16) * 1rem; // 24px\n\ntd,\nth {\n  vertical-align: top;\n}\n\ntable {\n  width: 100%;\n  border-collapse: collapse;\n  margin-top: spacing.$unit-lg;\n\n  caption {\n    padding: spacing.$unit-xs spacing.$unit-xs spacing.$unit-xs 0;\n    text-align: left;\n    font-size: toRem(14px);\n\n    &.lui-table-caption-bottom {\n      caption-side: bottom;\n    }\n  }\n\n  thead {\n    border-top: 1px solid colors.$gray;\n    //automatically style the th in a thead row, but for headers in a column, use the class name on a cell\n    th,\n    .lui-table-head-cell {\n      color: colors.$brand-secondary;\n      @include fonts.font-semibold;\n    }\n  }\n\n  tbody {\n    border-top: 1px solid colors.$gray;\n    border-bottom: 1px solid colors.$gray;\n  }\n\n  tr {\n    border-bottom: 1px solid colors.$lily;\n    //adding white border to the top so there is a clear division between rows when background colour changes on selection\n    &:not(:first-child) {\n      border-top: 1px solid #fff;\n    }\n  }\n\n  .lui-table-row-selected {\n    background-color: colors.$polar !important;\n  }\n\n  th {\n    font-weight: 500;\n  }\n\n  th,\n  td {\n    padding: spacing.$unit-sm spacing.$unit-xs;\n    text-align: left;\n    border-spacing: 0;\n    border: none;\n    margin: 0;\n  }\n\n  // Modify form elements in the table\n  label {\n    display: inline-block;\n    margin: 0;\n\n    .LuiDeprecatedForms & {\n      @include fonts.font-light;\n      display: inline-block;\n    }\n\n    @include fonts.font-light;\n\n    &:hover {\n      cursor: pointer;\n    }\n  }\n\n  // set the top position of checkboxes for proper alignment in tables\n  .lui-checkbox-container {\n    margin-top: 0;\n\n    input {\n      top: 0;\n    }\n  }\n}\n\n.lui-table-column-headers {\n  th {\n    @include fonts.font-regular;\n  }\n}\n\n// Zebra styling for tables and the alike. Some have a greater scope, while others are very specific\n.lui {\n  // Style all the alternating rows in a table with a zebra\n  &-table-zebra {\n    tr {\n      &:nth-child(even) {\n        background-color: colors.$hint;\n      }\n    }\n  }\n\n  // A class to apply the zebra styling to a specific tag. Could be a <tr>, a <div>, a <li>. Use your App logic for alternating styling between rows as there is no CSS to do this\n  &-row-zebra {\n    background-color: colors.$hint;\n  }\n\n  // To be applied on a <tbody> and only has scope for the rows within that level, it won\'t style child rows, so it won\'t affect nested tables\n  &-table-first-level-row-zebra > tr:nth-child(even) {\n    background-color: colors.$hint;\n  }\n}\n\n//use the following to set all cells in the first col to a width\n.lui-table-col-icon-row1 {\n  td {\n    &:first-child {\n      width: $icon-col-width;\n    }\n  }\n}\n\n//use the following to set all cells in the last col of the table to a width\n.lui-table-col-icon-last-row {\n  td {\n    &:last-child {\n      width: $icon-col-width;\n      text-align: right;\n    }\n  }\n}\n\n//Use to restrict the size of a td cell, rather than affecting the whold column like the ones above. Not applying this to a single cell will affect the whole column unless you specify sizes for the other cells in that column.\n.lui-table-icon-cell {\n  width: $icon-col-width;\n}\n',"@use '../../../scss/Core' as lui;\n@use \"../../Foundation/Variables/ColorVars.scss\" as colors;\n@use \"../../Foundation/Variables/FontVars.scss\" as fonts;\n@use \"../../Foundation/Utilities\" as *;\n\n.tippy-box {\n  @include drop-shadow(sm);\n  padding: lui.$unit-xxs lui.$unit-xs;\n  border-radius: 0;\n  text-align: left;\n  // If the tippy theme name contains '-withDelay' then add a CSS delay animation\n  &[data-theme*='-withDelay'] {\n    animation: fadeInToolTip 1.5s;\n  }\n\n  .tippy-content {\n    padding: 0;\n    font-size: toRem(12px);\n    @include fonts.font-semibold;\n\n    p {\n      font-size: toRem(12px);\n      margin-top: 1em;\n      @include fonts.font-semibold;\n    }\n\n    p:first-child {\n      margin-top: 0;\n    }\n  }\n}\n\n@keyframes fadeInToolTip {\n  0% {\n    opacity: 0;\n  }\n  66% {\n    opacity: 0;\n  }\n  100% {\n    opacity: 1;\n  }\n}\n\n// Using *= attribute selector to look for 'contains' so styling will be applied to both standard and delayed themes\n.tippy-box[data-theme*='default'] {\n  background: colors.$white;\n  .tippy-content {\n    color: colors.$charcoal;\n  }\n}\n\n.tippy-box[data-theme*='info'] {\n  background: colors.$teal;\n  .tippy-content {\n    color: colors.$white;\n  }\n}\n\n.tippy-box[data-theme*='error'] {\n  background: colors.$error;\n  .tippy-content {\n    color: colors.$white;\n  }\n}\n",'@use "../../Foundation/Variables/ColorVars.scss" as colors;\n@use "../../Foundation/Variables/FontVars.scss" as fonts;\n@use "../../Foundation/Variables/SpacingVars.scss"as spacing;\n@use "../../Foundation/Utilities" as *;\n\n/**\n * Here is where we can override the styles of react-menu\n */\n\n//.lui-menu .rc-menu__item {\n//  color: green;\n//}\n\n.lui-menu.szh-menu {\n  z-index: 900;\n  color: colors.$base-type-color;\n  @include fonts.font-light;\n\n  div,\n  a[role=\'menuitem\'] {\n    text-decoration: none;\n    color: colors.$base-type-color;\n    @include fonts.font-light;\n  }\n}\n\n/**\n * Here are styles for lui select menu\n */\n.lui-select-menu.szh-menu-container {\n  @include breakpoint(sm) {\n    position: absolute;\n  }\n}\n\n.lui-select-menu.szh-menu {\n  z-index: 900;\n  width: 92vw;\n  overflow-y: scroll;\n\n  @include breakpoint(sm) {\n    overflow: visible;\n    height: auto;\n    width: 240px;\n  }\n\n  color: colors.$base-type-color;\n  @include fonts.font-light;\n}\n\nli.lui-select-menuItem {\n  padding: spacing.$unit-xs spacing.$unit-sm spacing.$unit-xs spacing.$unit-xs;\n  display: flex;\n  line-height: 1;\n  transition: all 0.2s ease-in-out;\n  fill: colors.$fuscous;\n\n  &:hover {\n    background-color: colors.$polar;\n  }\n}\n\n.lui-select-menuItem--error {\n  p {\n    color: colors.$error;\n  }\n\n  .LuiIcon {\n    fill: colors.$error;\n  }\n}\n\n.lui-select-menuItemText {\n  @include fonts.font-regular();\n  color: colors.$charcoal;\n  margin: 0;\n  padding-left: spacing.$unit-lg;\n\n  //if no icon, give it 4px to align with the group header\n  &--noPadding {\n    padding-left: spacing.$unit-xxs;\n  }\n}\n\n.lui-select-wrapword {\n  min-width: 0;\n  word-break: break-all;\n}\n\n.lui-select-icon + .lui-select-menuItemText {\n  padding-left: spacing.$unit-xs;\n}\n\n.lui-switch-icon + .lui-select-menuItemText {\n  padding-left: spacing.$unit-xs;\n}\n\n.lui-switch-icon-checked {\n  fill: colors.$sea;\n}\n\nli.lui-select-menu-group {\n  height: 32px;\n  color: colors.$fuscous;\n  padding-left: 0.75rem;\n  text-transform: none;\n  @include fonts.font-semibold();\n}\n\n.lui-select-submenu {\n  flex: 1;\n  div[role=\'menuitem\'] {\n    padding: spacing.$unit-xs spacing.$unit-xs spacing.$unit-xs 2.5rem;\n    text-decoration: none;\n    @include fonts.font-regular();\n    height: 40px;\n  }\n  //overwrite the hover color\n  .szh-menu__item--hover {\n    background-color: colors.$polar;\n  }\n}\n\n.lui-select-submenu-with-icon {\n  flex: 1;\n  // width: 200px;\n  div[role=\'menuitem\'] {\n    padding-left: 0px;\n    text-decoration: none;\n    @include fonts.font-regular();\n    height: 40px;\n  }\n}\n\nli.lui-select-divider {\n  margin: 0.25rem;\n}\n\n.lui-menu-sub-header {\n  display: flex;\n  align-items: center;\n}\n\n.lui-menu-sub-header-icon {\n  margin: spacing.$unit-xs;\n  fill: colors.$fuscous;\n}\n','@use "../../Foundation/Variables/ColorVars.scss" as colors;\n@use "../../Foundation/Variables/FontVars.scss" as fonts;\n@use "../../Foundation/Variables/SpacingVars.scss" as spacing;\n@use "../../Foundation/Utilities/" as *;\n\n.lui {\n  &-expand {\n    &-container {\n      display: flex;\n      align-items: center;\n    }\n\n    &-header {\n      cursor: pointer;\n      user-select: none;\n      padding: spacing.$unit-sm 0 spacing.$unit-sm 0;\n      display: flex;\n      justify-content: space-between;\n      & h2,\n      h3,\n      h4,\n      h5,\n      h6 {\n        @include fonts.font-semibold;\n        width: auto;\n        font-size: 1.25rem;\n        margin: 0;\n      }\n      &:hover {\n        cursor: pointer;\n      }\n    }\n\n    &-icon {\n      align-self: center;\n      color: colors.$base-icon-color;\n      user-select: none;\n      // Define a transform so it can be animated when opening\n      transform: rotate(0deg);\n      transition: transform 0.3s ease(in-out-expo);\n\n      &:hover {\n        cursor: pointer;\n      }\n\n      &.lui-expand-icon-transform {\n        transform: rotate(180deg);\n      }\n    }\n  }\n\n  &-collapse-text {\n    overflow: hidden;\n    transition: height 0.3s ease(in-out-expo); // This doesn\'t do anything - needs to be max or min height\n    height: 0;\n\n    *:first-child {\n      margin-top: 0;\n    }\n  }\n\n  &-accordion-content {\n    transition: max-height 0.2s ease-in-out;\n    *:first-child {\n      margin-top: 0;\n    }\n  }\n}\n','@use "../../Core" as lui;\n@use "../../Foundation/Utilities" as *;\n\n// This builds on the NZ Govt footer SCSS which lives in a separate folder\n\n.lui-footer {\n  padding-top: lui.$unit-lg;\n  padding-bottom: lui.$unit-md;\n\n  padding-left: lui.$unit-md;\n  padding-right: lui.$unit-md;\n\n  // colour row dividers (border top)\n  div[class*=\'row-divider\'] {\n    border-color: lui.$surfie;\n  }\n\n  .lui-footer-columns {\n    @include breakpoint(md) {\n      display: flex;\n      justify-content: space-between;\n    }\n\n    @include breakpoint(md) {\n      flex-direction: row;\n      justify-content: space-between;\n      flex: 0 1 auto;\n    }\n  }\n\n  .lui-footer-container-right {\n    @include breakpoint(md) {\n      text-align: right;\n    }\n  }\n\n  h1,\n  h2,\n  h3,\n  h4,\n  p,\n  li,\n  a {\n    color: lui.$iceberg;\n  }\n\n  background-color: lui.$sherpa;\n\n  h1,\n  h2,\n  h3,\n  h4 {\n    margin-top: 0;\n    @include lui.font-regular;\n  }\n\n  a {\n    text-decoration: underline;\n\n    &:before {\n      display: none;\n    }\n\n    &:hover {\n      color: lui.$white;\n    }\n\n    &:visited {\n      color: lui.$silver;\n    }\n  }\n\n  .lui-footer-list {\n    list-style-type: none;\n    padding: 0;\n    margin: 0;\n\n    li {\n      margin-top: lui.$unit-sm;\n\n      a {\n        color: lui.$iceberg;\n      }\n    }\n  }\n\n  .lui-footer-inline-list-item {\n    display: block;\n    margin-right: 2.5rem;\n    margin-bottom: 1.5rem;\n\n    @include breakpoint(md) {\n      display: inline-block;\n    }\n  }\n\n  .lui-footer-logo-row {\n    margin-top: 0;\n\n    @include breakpoint(md) {\n      margin-top: lui.$unit-xl;\n    }\n  }\n\n  .lui-footer-nz-govt-logo,\n  .lui-footer-copyright {\n    text-align: left;\n    img {\n      height: toRem(56px);\n      width: auto;\n    }\n    @include breakpoint(md) {\n      text-align: right;\n    }\n  }\n\n  .lui-footer-nz-govt-logo {\n    margin-top: lui.$unit-xl;\n    @include breakpoint(md) {\n      text-align: right;\n      margin-top: lui.$unit-sm;\n    }\n  }\n\n  .lui-small {\n    text-align: left;\n\n    @include breakpoint(md) {\n      text-align: right;\n    }\n  }\n\n  // Target the GDS std footer class + lui-footer-sm to restyle. Trying to avoid rewrite of GDS scss and using overrides.\n  &.lui-footer-small {\n    padding: lui.$unit-xs lui.$unit-sm;\n  }\n}\n\n// -----------------------------------------------------------------------------\n// ---------------------- LUI App footer small  --------------------------------\n// -----------------------------------------------------------------------------\n\n$AppFooterSmlContainerBreakPointLg: 1100px;\n$AppFooterSmlContainerBreakPointMd: 860px;\n$FooterLogoHeight: toRem(56px);\n\n.luiAppFooter-sm {\n  container-type: inline-size;\n  container-name: appFooterSml;\n  background-color: lui.$sherpa;\n  min-height: $FooterLogoHeight;\n}\n\n.luiAppFooter-grid {\n  display: grid;\n  grid-template-columns: 1fr;\n  align-items: center;\n  padding: lui.$unit-md;\n  @container appFooterSml (inline-size >= #{$AppFooterSmlContainerBreakPointLg}) {\n    grid-template-columns: 1fr 240px;\n    padding: 0 lui.$unit-md;\n  }\n}\n\n.luiAppFooter-columnOne {\n  display: grid;\n  grid-template-columns: 1fr;\n  column-gap: lui.$unit-md;\n  row-gap: lui.$unit-sm;\n  @container appFooterSml (inline-size >= #{$AppFooterSmlContainerBreakPointMd}) {\n    grid-template-columns: 1fr 350px;\n  }\n  @container appFooterSml (inline-size >= #{$AppFooterSmlContainerBreakPointLg}) {\n    grid-template-columns: minmax(min-content, max-content) 350px;\n  }\n}\n\n.luiAppFooter-linksCell {\n  display: flex;\n  column-gap: lui.$unit-md;\n  flex-wrap: wrap;\n  a {\n    color: lui.$snow;\n    font-size: toRem(14px);\n    @include lui.font-regular();\n    text-decoration: none;\n    line-height: toRem(24px);\n    &:hover {\n      text-decoration: underline;\n    }\n  }\n}\n\n.luiAppFooter-copyright {\n  color: lui.$snow;\n  font-size: toRem(14px);\n  @include lui.font-regular();\n  line-height: toRem(24px);\n  opacity: 0.8;\n  margin: 0;\n}\n\n.luiAppFooter-nzGovtLogo {\n  justify-self: start;\n  font-size: 0; //remove whitespace\n  @container appFooterSml (inline-size >= #{$AppFooterSmlContainerBreakPointLg}) {\n    justify-self: end;\n  }\n  img {\n    height: $FooterLogoHeight;\n    width: auto;\n  }\n}\n','@use "../../Foundation/Variables/MiscVars.scss" as misc;\n@use "../../Foundation/Variables/ColorVars.scss" as colors;\n@use "../../Foundation/Variables/FontVars.scss" as fonts;\n@use "../../Foundation/Variables/SpacingVars.scss" as spacing;\n@use "../../Foundation/Utilities" as *;\n\n$headerRowHeightSm: 60px;\n$headerRowHeightMd: 85px;\n$headerRowHeightLg: 110px;\n$swishHeightSm: 3px;\n$swishHeightLg: 6px;\n// header height is row height + swish height\n// columns in header row is always 100% so it\'s row and swish that drives the height of the header\n$headerHeightSm: $headerRowHeightSm + $swishHeightSm;\n$headerHeightMd: $headerRowHeightMd + $swishHeightLg;\n$headerHeightLg: $headerRowHeightLg + $swishHeightLg;\n\n.lui-header {\n  @include lui-standard-header-background($swishHeightLg);\n}\n\n.lui-header-row {\n  display: flex;\n  justify-content: space-between;\n  align-items: center;\n  height: $headerRowHeightMd;\n  padding-left: toRem(24px);\n  padding-right: toRem(24px);\n  padding-top: spacing.$unit-xs;\n  padding-bottom: spacing.$unit-xs;\n\n  @include breakpoint(md) {\n    padding-left: toRem(36px);\n    padding-right: toRem(36px);\n    height: $headerRowHeightLg;\n  }\n\n  @include breakpoint(xl) {\n    padding-left: toRem(48px);\n    padding-right: toRem(48px);\n  }\n}\n\n.lui-header-col {\n  display: flex;\n  align-items: center;\n  flex-wrap: nowrap;\n  flex: 0 1 auto;\n  height: 100%;\n}\n\n.lui-header-menu-item {\n  margin-left: spacing.$unit-lg;\n}\n\n.lui-header-title {\n  padding-left: spacing.$unit-lg;\n  white-space: nowrap;\n\n  h1 {\n    color: colors.$white;\n    @media only screen {\n      //I\'ve wrapped this in a media query so it will still print out on a page\n      display: none;\n    }\n    @include breakpoint(sm) {\n      display: block;\n      font-size: 2rem;\n      line-height: 2rem; //line height same as size so vertical placement is true\n      @include fonts.font-light;\n      margin: 0;\n    }\n    @include breakpoint(md) {\n      font-size: 2.25rem;\n      line-height: 2.25rem; //line height same as size so vertical placement is true\n    }\n  }\n}\n\n.lui-header-logo {\n  margin-left: spacing.$unit-xs;\n\n  a:before {\n    display: none;\n  }\n\n  @include breakpoint(sm) {\n    margin-left: 0;\n    padding-right: spacing.$unit-lg;\n    border-right: 1px solid colors.$persian;\n  }\n\n  & .clickable {\n    cursor: pointer;\n  }\n}\n\n.linz-logo {\n  width: 170px;\n  @include breakpoint(sm) {\n    width: 200px;\n  }\n}\n\n.lui-header-small {\n  .lui-header-row {\n    height: $headerRowHeightSm;\n\n    .lui-header-col {\n      height: 40px;\n\n      .lui-header-logo {\n        border: none;\n      }\n\n      .linz-motif {\n        height: 32px;\n      }\n    }\n  }\n\n  &:after {\n    height: $swishHeightSm;\n  }\n}\n\n.lui-header-sticky {\n  position: fixed;\n  z-index: 50;\n  top: 0;\n  left: 0;\n  width: 100%;\n\n  & + div,\n  & + main {\n    margin-top: $headerHeightMd;\n\n    @include breakpoint(md) {\n      margin-top: $headerHeightLg;\n    }\n  }\n\n  &.lui-header-small {\n    & + div,\n    & + main {\n      margin-top: $headerHeightSm;\n    }\n  }\n}\n\n.lui-header-menu-item {\n  position: relative;\n\n  .lui-header-menu-icon {\n    @include fonts.font-semibold;\n    position: relative;\n    display: flex;\n    align-items: center;\n    color: colors.$white;\n    cursor: default;\n    user-select: none;\n\n    &.clickable:hover {\n      cursor: pointer;\n    }\n\n    .lui-menu-label {\n      text-align: left;\n      padding-left: 10px;\n    }\n\n    i {\n      font-size: toRem(32px);\n    }\n\n    .badge {\n      position: absolute;\n      top: -0.3rem;\n      left: 1.2rem;\n      width: 1.3rem;\n      height: 1.3rem;\n      font-size: 0.8em;\n    }\n  }\n}\n\n.badge {\n  display: block;\n  text-align: center;\n  border-radius: 50%;\n  background: #cc0000;\n  color: white;\n}\n',"@use \"../../Foundation/Variables/ColorVars.scss\" as colors;\n\n// ============\n// Lui Standard Header Background\n// ============\n\n//   🤔 don't need this as a Util - highly specific, should be with header\n\n@mixin lui-standard-header-background($swish-height) {\n  background: colors.$linz-linear-gradient-blue;\n  color: #fff;\n\n  &:after {\n    width: 100%;\n    content: '';\n    display: block;\n    height: $swish-height;\n    overflow: hidden;\n    background: colors.$linz-linear-gradient-teal;\n  }\n\n  &.lui-header-transparent {\n    background: transparent;\n    color: colors.$sea;\n    &:after {\n      content: none;\n    }\n    .lui-header-menu-icon {\n      color: colors.$surfie;\n    }\n  }\n}\n",'@use "../../Foundation/Variables/MiscVars.scss" as misc;\n@use "../../Foundation/Variables/ColorVars.scss" as colors;\n@use "../../Foundation/Variables/FontVars.scss" as fonts;\n@use "../../Foundation/Variables/SpacingVars.scss" as spacing;\n@use "../../Foundation/Utilities" as *;\n\n$headerRowHeightSmV2: 56px;\n$headerRowHeightMdV2: 85px;\n$headerRowHeightLgV2: 110px;\n$swishHeightSmV2: 3px;\n$swishHeightLgV2: 6px;\n// header height is row height + swish height\n// columns in header row is always 100% so it\'s row and swish that drives the height of the header\n$headerHeightSmV2: $headerRowHeightSmV2; // doesn\'t apply swish to small header\n$headerHeightMdV2: $headerRowHeightMdV2 + $swishHeightLgV2;\n$headerHeightLgV2: $headerRowHeightLgV2 + $swishHeightLgV2;\n\n$headerPadding: spacing.$unit-xxs;\n\n// the padding (margin) size for the menu logo, icon and heading text\n$headerElementPadding: spacing.$unit-xs;\n\n.LuiHeaderV2 {\n  background: colors.$linz-linear-gradient-blue;\n  color: #fff;\n\n  &:after {\n    width: 100%;\n    content: \'\';\n    display: block;\n    height: $swishHeightLgV2;\n    overflow: hidden;\n    background: colors.$linz-linear-gradient-teal;\n  }\n\n  &.LuiHeaderV2-transparent {\n    background: transparent;\n    color: colors.$sea;\n    &:after {\n      content: none;\n    }\n    .LuiHeaderV2-menu-item-button {\n      &-icon {\n        color: colors.$surfie;\n      }\n    }\n  }\n}\n\n.LuiHeaderV2-row {\n  display: flex;\n  justify-content: space-between;\n  align-items: center;\n  height: $headerRowHeightMdV2;\n  padding: $headerPadding;\n}\n\n.LuiHeaderV2-col {\n  display: flex;\n  align-items: center;\n  flex-wrap: nowrap;\n  flex: 0 1 auto;\n  height: 100%;\n  column-gap: $headerPadding;\n}\n\n.LuiHeaderV2-title {\n  white-space: nowrap;\n  padding-right: $headerElementPadding;\n  padding-left: $headerElementPadding;\n\n  vertical-align: middle;\n\n  h1 {\n    color: colors.$white;\n    @media only screen {\n      display: none;\n    }\n    @include breakpoint(sm) {\n      display: block;\n      font-size: 2rem;\n      line-height: 2rem; // line height same as size so vertical placement is true\n      @include fonts.font-light;\n      margin: 0;\n    }\n    @include breakpoint(md) {\n      font-size: 2.25rem;\n      line-height: 2.25rem; // line height same as size so vertical placement is true\n    }\n  }\n}\n\n.LuiHeaderV2-logo {\n  a:before {\n    display: none;\n  }\n\n  margin-left: $headerElementPadding;\n  margin-right: $headerElementPadding;\n\n  @include breakpoint(sm) {\n    border-right: 1px solid colors.$persian;\n    margin-right: $headerElementPadding;\n  }\n\n  .clickable {\n    cursor: pointer;\n  }\n}\n\n.LuiHeaderV2-linz-logo {\n  width: 170px;\n  @include breakpoint(sm) {\n    width: 200px;\n  }\n  vertical-align: middle;\n}\n\n.LuiHeaderV2-small {\n  .LuiHeaderV2-row {\n    height: $headerRowHeightSmV2;\n\n    .LuiHeaderV2-col {\n      .LuiHeaderV2-logo {\n        border: none;\n      }\n\n      .LuiHeaderV2-linz-motif {\n        height: 32px;\n        width: 32px;\n        vertical-align: middle;\n      }\n\n      .LuiHeaderV2-title {\n        white-space: nowrap;\n\n        h1 {\n          color: colors.$white;\n          font-size: 20px;\n          line-height: 24px;\n          @include fonts.font-regular;\n        }\n      }\n    }\n  }\n\n  &:after {\n    // doesn\'t apply swish gap to small header\n    content: none;\n  }\n}\n\n.LuiHeaderV2-sticky {\n  position: fixed;\n  z-index: 50;\n  top: 0;\n  left: 0;\n  width: 100%;\n\n  & + div,\n  & + main {\n    margin-top: $headerHeightMdV2;\n\n    @include breakpoint(md) {\n      margin-top: $headerHeightLgV2;\n    }\n  }\n\n  &.LuiHeaderV2-small {\n    & + div,\n    & + main {\n      margin-top: $headerHeightSmV2;\n    }\n  }\n}\n\n.LuiHeaderV2-non-sticky {\n  width: 100%;\n}\n\n.LuiHeaderV2-menu-item {\n  display: flex;\n  flex-direction: column;\n\n  .clickable:hover {\n    cursor: pointer;\n  }\n\n  &-button {\n    @include fonts.font-semibold;\n    position: relative;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    border-radius: misc.$borderRadius;\n\n    &.selected {\n      background-color: rgba(0, 0, 0, 0.2);\n    }\n\n    &.unselected:hover {\n      background-color: rgba(255, 255, 255, 0.2);\n    }\n\n    .menu-tooltip {\n      display: none;\n      background-color: black;\n      text-align: center;\n      border-radius: 4px;\n      padding: 6px 6px;\n      @include fonts.font-regular;\n      font-size: 14px;\n      white-space: nowrap;\n\n      position: absolute;\n      top: 60px;\n      z-index: 10;\n\n      @include drop-shadow(sm);\n      border-radius: misc.$borderRadius;\n\n      &.dark {\n        color: colors.$hint;\n        background-color: colors.$charcoal;\n      }\n      &.light {\n        color: colors.$charcoal;\n        background-color: colors.$hint;\n      }\n      &.left {\n        left: 8px;\n      }\n      &.right {\n        right: 8px;\n      }\n\n      &::after {\n        content: \'\';\n        position: absolute;\n        top: -14px;\n        border-width: 8px;\n        border-style: solid;\n      }\n\n      &.left:after {\n        left: 0;\n      }\n\n      &.right:after {\n        right: 0;\n      }\n\n      &.dark::after {\n        border-color: transparent transparent colors.$charcoal transparent;\n      }\n\n      &.light::after {\n        border-color: transparent transparent colors.$hint transparent;\n      }\n    }\n\n    &:hover {\n      .menu-tooltip {\n        display: block;\n      }\n    }\n\n    &-icon {\n      display: flex;\n      align-items: center;\n      color: colors.$white;\n      cursor: default;\n      user-select: none;\n\n      width: spacing.$unit-xl;\n      height: spacing.$unit-xl;\n      align-items: center;\n      justify-content: center;\n    }\n\n    &-label {\n      text-align: left;\n      white-space: nowrap;\n      padding-right: $headerElementPadding;\n    }\n\n    &-label-only {\n      display: flex;\n      justify-content: center;\n      align-items: center;\n      padding-left: $headerElementPadding;\n      padding-right: $headerElementPadding;\n      white-space: nowrap;\n      height: 48px;\n      @include fonts.font-semibold;\n      font-size: 16px;\n    }\n\n    &-badge {\n      position: absolute;\n      display: flex;\n      justify-content: center;\n      align-items: center;\n      top: 4px;\n      left: 25px;\n      width: 20px;\n      height: 20px;\n      font-size: 12px;\n      text-align: center;\n      border-radius: 50%;\n      background: #cc0000;\n      color: white;\n    }\n  }\n}\n','@use "../../Foundation/Variables/ColorVars.scss" as colors;\n@use "../../Foundation/Variables/FontVars.scss" as fonts;\n@use "../../Foundation/Variables/MiscVars.scss" as misc;\n@use "../../Foundation/Variables/SpacingVars.scss" as spacing;\n@use "../../Foundation/Utilities" as *;\n\n.lui-help-section {\n  ol.lui-help-numbering {\n    list-style: none;\n    margin: 0;\n    padding: 0;\n    li {\n      counter-increment: lui-list-counter;\n      position: relative;\n      margin: spacing.$unit-xl 0 0 spacing.$unit-xl;\n      p:first-child {\n        @include fonts.font-regular;\n      }\n      &:before {\n        content: counter(lui-list-counter);\n        position: absolute;\n        top: 0;\n        left: (-(spacing.$unit-xl));\n        font-size: 1.5rem;\n        font-weight: 500;\n        color: colors.$brand-secondary;\n        width: 20px;\n        height: 32px;\n        border-right: 1px solid colors.$silver;\n        font-size: toRem(18px);\n        @include breakpoint(md) {\n          width: 30px;\n        }\n      }\n    }\n  }\n  img {\n    margin: spacing.$unit-sm 0 0 0;\n    height: auto;\n    width: 75%;\n    //max width is set on the image, but this could change in the future by standarising the images\n  }\n}\n','@use "../../Foundation/Variables/MiscVars.scss" as misc;\n@use "../../Foundation/Variables/ColorVars.scss" as colors;\n@use \'../../Foundation/Variables/FontVars.scss\' as fonts;\n@use "../../Foundation/Utilities" as *;\n@use "../Header/header.scss" as header;\n\n@mixin menu-container {\n  text-align: left;\n  background-color: white;\n  color: colors.$base-type-color;\n}\n\n.lui-menu-close-button {\n  &:hover {\n    cursor: pointer;\n  }\n}\n\nbody.lui-menu-drawer-open {\n  overflow-y: hidden;\n}\n\n.lui-menu-drawer {\n  @include menu-container;\n  height: 100%;\n  width: 300px;\n  max-width: 100%;\n  position: fixed;\n  z-index: 1;\n  top: 0;\n  right: 0;\n  overflow-x: hidden;\n  border-left: 2px solid colors.$lily;\n  transition: right 0.5s, visibility 0.6s;\n\n  .lui-header & {\n    top: header.$headerHeightMd;\n    height: calc(100% - #{header.$headerHeightMd});\n\n    @include breakpoint(md) {\n      top: header.$headerHeightLg;\n      height: calc(100% - #{header.$headerHeightLg});\n    }\n  }\n\n  .lui-header-small & {\n    top: header.$headerHeightSm;\n    height: calc(100% - #{header.$headerHeightSm});\n  }\n\n  &-closed {\n    right: -300px;\n    visibility: hidden;\n  }\n\n  &-options {\n    hr {\n      background-color: colors.$lily;\n    }\n  }\n\n  &-option {\n    display: flex;\n    justify-content: space-between;\n    padding: 12px 16px;\n\n    &:hover {\n      cursor: pointer;\n      background-color: colors.$polar;\n    }\n\n    &-label {\n      display: flex;\n      align-items: center;\n\n      :first-child {\n        margin-right: 10px;\n      }\n\n      i {\n        color: colors.$brand-secondary;\n        font-size: toRem(24px);\n      }\n    }\n\n    .badge {\n      width: 24px;\n      height: 24px;\n    }\n  }\n}\n\n.lui-menu-dropdown {\n  @include menu-container;\n  position: absolute;\n  width: 350px;\n  border-radius: misc.$borderRadius;\n  right: 0;\n  top: toRem(32px); // same as menu item font size\n\n  &-closed {\n    display: none;\n  }\n\n  z-index: 900; // primary menu\n}\n\n.LuiDrawerMenuSection-header {\n  @include fonts.font-semibold;\n  background-color: colors.$hint;\n  white-space: nowrap;\n  padding-left: 16px;\n  padding-right: 8px;\n}\n\n.LuiDrawerMenuSection-header .lui-expand-header {\n  padding-top: 8px;\n  padding-bottom: 8px;\n  display: flex;\n}\n\n.LuiDrawerMenuSection-header h3 {\n  @include fonts.font-semibold;\n  font-size: fonts.$base-font-size;\n  color: colors.$base-type-color;\n  margin-top: 0;\n  line-height: 32px;\n}\n\n.LuiDrawerMenuDivider {\n  height: 1px;\n  background-color: colors.$lily;\n}\n','@use "../../Foundation/Variables/MiscVars.scss" as misc;\n@use "../../Foundation/Variables/ColorVars.scss" as colors;\n@use \'../../Foundation/Variables/FontVars.scss\' as fonts;\n@use "../../Foundation/Variables/SpacingVars.scss" as spacing;\n@use "../../Foundation/Utilities" as *;\n@use "../HeaderV2/header-v2.scss" as header;\n\n@mixin LuiHeaderMenuV2-drop-content {\n  text-align: left;\n  background-color: white;\n  color: colors.$base-type-color;\n  @include drop-shadow();\n  border-radius: misc.$borderRadius;\n}\n\nbody.LuiHeaderMenuV2-drawer-open {\n  overflow-y: hidden;\n}\n\n.LuiHeaderMenuV2-drawer-container {\n  position: relative;\n\n  &.drawer {\n    right: -(header.$headerPadding);\n  }\n\n  .LuiHeaderMenuV2-drawer {\n    @include LuiHeaderMenuV2-drop-content;\n    height: auto;\n    z-index: 900;\n\n    &.sm {\n      width: 260px;\n    }\n    &.md {\n      width: 280px;\n    }\n    &.lg {\n      width: 300px;\n    }\n    &.xlg {\n      width: 320px;\n    }\n\n    // dropdown drawer\n    &.dropdown {\n      display: none;\n      position: absolute;\n      right: 0;\n      &.open {\n        display: block;\n      }\n    }\n\n    // sliding drawer\n    .LuiHeaderV2 & {\n      &.drawer {\n        &.sticky {\n          position: fixed;\n          top: header.$headerHeightMdV2;\n        }\n      }\n\n      &.drawer {\n        &.non-sticky {\n          position: absolute;\n          top: header.$headerPadding;\n        }\n      }\n    }\n\n    .LuiHeaderV2-small & {\n      &.drawer {\n        &.sticky {\n          position: fixed;\n          top: header.$headerHeightSmV2;\n        }\n      }\n\n      &.drawer {\n        &.non-sticky {\n          position: absolute;\n          top: header.$headerPadding;\n        }\n      }\n    }\n\n    &.drawer {\n      &.sm {\n        right: -260px;\n      }\n      &.md {\n        right: -280px;\n      }\n      &.lg {\n        right: -300px;\n      }\n      &.xlg {\n        right: -320px;\n      }\n\n      // animation\n      transition: right 500ms, visibility 500ms;\n      visibility: hidden;\n\n      &.open {\n        right: 0px;\n        visibility: visible;\n      }\n    }\n\n    // drawer option and options\n    &-options {\n      hr {\n        background-color: colors.$lily;\n      }\n    }\n\n    &-option {\n      display: flex;\n      justify-content: space-between;\n      align-items: center;\n      padding: 12px 16px;\n      a {\n        text-decoration: none;\n        color: inherit;\n        font-weight: inherit;\n      }\n\n      &:hover {\n        cursor: pointer;\n        background-color: colors.$polar;\n      }\n\n      &-label {\n        display: flex;\n        align-i